import { StudentProfile, User, Role } from '../types';

// Mock Data Keys
const USERS_KEY = 'uniprofile_users';
const PROFILES_KEY = 'uniprofile_profiles';

// Initialize Admin if not exists
const initStorage = () => {
  const users = localStorage.getItem(USERS_KEY);
  if (!users) {
    const adminUser: User = {
      id: 'admin-1',
      username: 'admin',
      role: Role.ADMIN,
      name: 'College Admin'
    };
    // In a real app, password would be hashed. Storing plain for mock.
    // We'll store a separate "auth" map for passwords in a real mock, 
    // but here we will just assume a hardcoded password for admin check.
    localStorage.setItem(USERS_KEY, JSON.stringify([adminUser]));
  }
};

initStorage();

export const getUsers = (): User[] => {
  return JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
};

export const saveUser = (user: User) => {
  const users = getUsers();
  users.push(user);
  localStorage.setItem(USERS_KEY, JSON.stringify(users));
};

export const getProfiles = (): StudentProfile[] => {
  return JSON.parse(localStorage.getItem(PROFILES_KEY) || '[]');
};

export const getProfileByRollNo = (rollNo: string): StudentProfile | undefined => {
  const profiles = getProfiles();
  return profiles.find(p => p.rollNumber === rollNo);
};

export const saveProfile = (profile: StudentProfile) => {
  const profiles = getProfiles();
  const index = profiles.findIndex(p => p.id === profile.id);

  if (index >= 0) {
    profiles[index] = profile;
  } else {
    profiles.push(profile);
  }

  localStorage.setItem(PROFILES_KEY, JSON.stringify(profiles));
};

// File handling helper (Mock)
// We use blob URLs in memory for the session, but since we can't persist blobs easily 
// across reloads without IndexedDB, we will just simulate persistence for metadata 
// and lose the actual file preview on reload for this demo, OR we can use very small base64.
// For the purpose of this "World-Class" demo, I will assume the user stays in session 
// or re-uploads.
export const formatBytes = (bytes: number, decimals = 2) => {
  if (bytes === 0) return '0 Bytes';
  const k = 1024;
  const dm = decimals < 0 ? 0 : decimals;
  const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'outline' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  className = '', 
  isLoading,
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-lg font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:pointer-events-none";

  const variants = {
    primary: "bg-purple-600 text-white hover:bg-purple-700 focus:ring-purple-500",
    secondary: "bg-white text-gray-700 border border-gray-300 hover:bg-gray-50 focus:ring-purple-500",
    danger: "bg-red-600 text-white hover:bg-red-700 focus:ring-red-500",
    outline: "border-2 border-purple-600 text-purple-600 hover:bg-purple-50 focus:ring-purple-500",
    ghost: "text-gray-600 hover:bg-gray-100 hover:text-gray-900 focus:ring-gray-500"
  };

  const sizes = {
    sm: "h-9 px-3 text-sm",
    md: "h-10 px-4 py-2",
    lg: "h-12 px-6 text-lg"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading ? (
        <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      ) : null}
      {children}
    </button>
  );
};

