import { Input } from '../components/ui/Input';
import { Button } from '../components/ui/Button';
import { GraduationCap, ShieldCheck, Lock } from 'lucide-react';

const Login: React.FC = () => {
  const [role, setRole] = useState<Role>(Role.STUDENT);
