import React, { useState, useContext } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { AuthContext } from '../App';
import { Role, StudentProfile } from '../types';
import { saveUser, saveProfile, getUsers } from '../services/storage';
import { Input, Select } from '../components/ui/Input';
import { Button } from '../components/ui/Button';
import { GraduationCap } from 'lucide-react';

const Register: React.FC = () => {
  const navigate = useNavigate();
  const { login } = useContext(AuthContext);
  const [formData, setFormData] = useState({
    fullName: '',
    rollNumber: '',
    department: '',
    email: '',
    phone: '',
    password: '',
    confirmPassword: '',
    gender: 'Male',
    year: '1'
  });
  const [error, setError] = useState('');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const validate = () => {
    // Unique Roll No
    const users = getUsers();
    if (users.find(u => u.username === formData.rollNumber)) {
      return "Roll Number already registered";
    }

    // Email Domain
    if (!formData.email.endsWith('@bitsathy.ac.in')) {
      return "Email must be a valid college ID (@bitsathy.ac.in)";
    }

    // Phone
    if (!/^\d{10}$/.test(formData.phone)) {
      return "Phone number must be exactly 10 digits";
    }

    // Passwords
    if (formData.password !== formData.confirmPassword) {
      return "Passwords do not match";
    }
    if (formData.password.length < 6) {
      return "Password must be at least 6 characters";
    }

    return null;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const validationError = validate();
    if (validationError) {
      setError(validationError);
      return;
    }

    // Create User
    const newUser = {
      id: `std-${Date.now()}`,
      username: formData.rollNumber,
      role: Role.STUDENT,
      name: formData.fullName
    };

    // Store Auth (Simulated DB)
    const authDb = JSON.parse(localStorage.getItem('uniprofile_auth_db') || '{}');
    authDb[newUser.id] = formData.password;
    localStorage.setItem('uniprofile_auth_db', JSON.stringify(authDb));

    // Create Profile
    const newProfile: StudentProfile = {
      id: newUser.id,
      userId: newUser.id,
      fullName: formData.fullName,
      rollNumber: formData.rollNumber,
      department: formData.department,
      email: formData.email,
      phone: formData.phone,
      year: formData.year,
      gender: formData.gender as any,
      education: [],
      skills: [],
      projects: [],
      documents: [],
      certifications: []
    };

    saveUser(newUser);
    saveProfile(newProfile);

    // Auto login
    login(newUser);
    navigate('/student/profile');
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-2xl w-full space-y-8 bg-white p-8 rounded-xl shadow-lg border border-purple-100">
        <div className="text-center">
          <div className="mx-auto h-12 w-12 bg-purple-100 rounded-full flex items-center justify-center">
            <GraduationCap className="h-8 w-8 text-purple-600" />
          </div>
          <h2 className="mt-6 text-3xl font-extrabold text-gray-900">
            Student Registration
          </h2>
          <p className="mt-2 text-sm text-gray-600">
            Create your account to manage your profile
          </p>
        </div>

        <form className="mt-8 space-y-6" onSubmit={handleSubmit}>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <Input
              label="Full Name"
              name="fullName"
              required
              value={formData.fullName}
              onChange={handleChange}
            />
            <Input
              label="Roll Number"
              name="rollNumber"
              required
              value={formData.rollNumber}
              onChange={handleChange}
            />
            <Input
              label="College Email"
              type="email"
              name="email"
              required
              value={formData.email}
              onChange={handleChange}
              placeholder="example@bitsathy.ac.in"
            />
            <Input
              label="Phone Number"
              type="tel"
              name="phone"
              required
              value={formData.phone}
              onChange={handleChange}
              maxLength={10}
            />
            <Select
              label="Department"
              name="department"
              required
              value={formData.department}
              onChange={handleChange}
              options={[
                { value: 'CSE', label: 'Computer Science' },
                { value: 'IT', label: 'Information Technology' },
                { value: 'ECE', label: 'Electronics & Communication' },
                { value: 'EEE', label: 'Electrical & Electronics' },
                { value: 'MECH', label: 'Mechanical Engineering' },
                { value: 'CIVIL', label: 'Civil Engineering' }
              ]}
            />
            <Select
              label="Year / Batch"
              name="year"
              required
              value={formData.year}
              onChange={handleChange}
              options={[
                { value: '1', label: '1st Year' },
                { value: '2', label: '2nd Year' },
                { value: '3', label: '3rd Year' },
                { value: '4', label: '4th Year' }
              ]}
            />
            <Select
              label="Gender"
              name="gender"
              required
              value={formData.gender}
              onChange={handleChange}
              options={[
                { value: 'Male', label: 'Male' },
                { value: 'Female', label: 'Female' },
                { value: 'Other', label: 'Other' }
              ]}
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-4 border-t">
             <Input
              label="Password"
              type="password"
              name="password"
              required
              value={formData.password}
              onChange={handleChange}
            />
             <Input
              label="Confirm Password"
              type="password"
              name="confirmPassword"
              required
              value={formData.confirmPassword}
              onChange={handleChange}
            />
          </div>

          {error && (
            <div className="text-red-500 text-sm text-center bg-red-50 p-2 rounded">
              {error}
            </div>
          )}

          <div className="flex gap-4">
             <Button type="button" variant="secondary" className="w-full" onClick={() => navigate('/login')}>
              Back to Login
            </Button>
            <Button type="submit" className="w-full">
              Register
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Register;

