export default StudentLayout;

import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../../App';
import { getProfileByRollNo, saveProfile } from '../../services/storage';
import { StudentProfile as IStudentProfile } from '../../types';
import { Button } from '../../components/ui/Button';
import { Input, Select } from '../../components/ui/Input';
import { Camera, Save, Lock } from 'lucide-react';

const Profile: React.FC = () => {
  const { user } = useContext(AuthContext);
  const [profile, setProfile] = useState<IStudentProfile | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [loading, setLoading] = useState(true);
  const [msg, setMsg] = useState({ type: '', text: '' });

  useEffect(() => {
    if (user) {
      const data = getProfileByRollNo(user.username);
      if (data) setProfile(data);
      setLoading(false);
    }
  }, [user]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (profile) {
      saveProfile(profile);
      setMsg({ type: 'success', text: 'Profile updated successfully!' });
      setIsEditing(false);
      setTimeout(() => setMsg({ type: '', text: '' }), 3000);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    if (profile) {
      setProfile({ ...profile, [e.target.name]: e.target.value });
    }
  };

  // Mock Photo Upload
  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && profile) {
      const url = URL.createObjectURL(file);
      setProfile({ ...profile, profilePhoto: url });
    }
  };

  if (loading) return <div>Loading...</div>;
  if (!profile) return <div>Profile not found</div>;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
           <h1 className="text-2xl font-bold text-gray-900">My Profile</h1>
           <p className="text-gray-500">Manage your personal information</p>
        </div>
        {!isEditing ? (
          <Button onClick={() => setIsEditing(true)}>Edit Profile</Button>
        ) : (
          <div className="flex gap-2">
            <Button variant="secondary" onClick={() => setIsEditing(false)}>Cancel</Button>
            <Button form="profile-form" type="submit">
              <Save className="w-4 h-4 mr-2" /> Save Changes
            </Button>
          </div>
        )}
      </div>

      {msg.text && (
        <div className={`p-4 rounded-lg ${msg.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
          {msg.text}
        </div>
      )}

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="h-32 bg-purple-600"></div>
        <div className="px-8 pb-8">
          <div className="relative flex justify-between items-end -mt-12 mb-6">
            <div className="relative group">
              <div className="h-24 w-24 rounded-full border-4 border-white bg-white overflow-hidden shadow-md">
                {profile.profilePhoto ? (
                  <img src={profile.profilePhoto} alt="Profile" className="h-full w-full object-cover" />
                ) : (
                  <div className="h-full w-full bg-gray-200 flex items-center justify-center text-gray-400">
                    <Camera className="w-8 h-8" />
                  </div>
                )}
              </div>
              {isEditing && (
                <label className="absolute bottom-0 right-0 p-1.5 bg-purple-600 text-white rounded-full cursor-pointer hover:bg-purple-700 shadow-sm transition-transform hover:scale-105">
                  <Camera className="w-4 h-4" />
                  <input type="file" className="hidden" accept="image/*" onChange={handlePhotoUpload} />
                </label>
              )}
            </div>
          </div>

          <form id="profile-form" onSubmit={handleSave} className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-1">
              <label className="text-sm font-medium text-gray-700">Roll Number</label>
              <div className="flex items-center px-3 py-2 border border-gray-200 bg-gray-50 rounded-lg text-gray-500 cursor-not-allowed">
                <Lock className="w-4 h-4 mr-2 opacity-50" />
                {profile.rollNumber}
              </div>
            </div>

            <div className="space-y-1">
               <label className="text-sm font-medium text-gray-700">College Email</label>
               <div className="px-3 py-2 border border-gray-200 bg-gray-50 rounded-lg text-gray-500 cursor-not-allowed">
                {profile.email}
              </div>
            </div>

            <Input
              label="Full Name"
              name="fullName"
              value={profile.fullName}
              onChange={handleChange}
              disabled={!isEditing}
            />

            <Input
              label="Phone Number"
              name="phone"
              value={profile.phone}
              onChange={handleChange}
              disabled={!isEditing}
            />

            <Select
              label="Department"
              name="department"
              value={profile.department}
              onChange={handleChange}
              disabled={!isEditing}
              options={[
                { value: 'CSE', label: 'Computer Science' },
                { value: 'IT', label: 'Information Technology' },
                { value: 'ECE', label: 'Electronics & Communication' },
                { value: 'EEE', label: 'Electrical & Electronics' },
                { value: 'MECH', label: 'Mechanical Engineering' },
                { value: 'CIVIL', label: 'Civil Engineering' }
              ]}
            />

            <Select
              label="Year / Batch"
              name="year"
              value={profile.year}
              onChange={handleChange}
              disabled={!isEditing}
              options={[
                { value: '1', label: '1st Year' },
                { value: '2', label: '2nd Year' },
                { value: '3', label: '3rd Year' },
                { value: '4', label: '4th Year' }
              ]}
            />

            <div className="md:col-span-2">
              <h3 className="text-lg font-medium text-gray-900 mb-4 mt-4">Social Links</h3>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                 <Input
                  label="GitHub Profile"
                  name="githubLink"
                  placeholder="https://github.com/username"
                  value={profile.githubLink || ''}
                  onChange={handleChange}
                  disabled={!isEditing}
                />
                 <Input
                  label="LinkedIn Profile"
                  name="linkedinLink"
                  placeholder="https://linkedin.com/in/username"
                  value={profile.linkedinLink || ''}
                  onChange={handleChange}
                  disabled={!isEditing}
                />
                 <Input
                  label="Portfolio / Website"
                  name="portfolioLink"
                  placeholder="https://yourportfolio.com"
                  value={profile.portfolioLink || ''}
                  onChange={handleChange}
                  disabled={!isEditing}
                />
              </div>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Profile;

import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../../App';
import { getProfileByRollNo, saveProfile, formatBytes } from '../../services/storage';
import { StudentProfile, Document } from '../../types';
import { Button } from '../../components/ui/Button';
import { Upload, Trash2, Eye, FileText, Image as ImageIcon, X } from 'lucide-react';

const Documents: React.FC = () => {
  const { user } = useContext(AuthContext);
  const [profile, setProfile] = useState<StudentProfile | null>(null);
  const [uploadType, setUploadType] = useState<Document['type']>('Resume');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewDoc, setPreviewDoc] = useState<Document | null>(null);

  useEffect(() => {
    if (user) {
      const data = getProfileByRollNo(user.username);
      if (data) setProfile(data);
    }
  }, [user]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      // Validation: Check size (5MB limit for mock) and type
      if (file.size > 5 * 1024 * 1024) {
        alert("File too large. Max 5MB.");
        return;
      }
      setSelectedFile(file);
    }
  };

  const handleUpload = () => {
    if (!selectedFile || !profile) return;

    const newDoc: Document = {
      id: `doc-${Date.now()}`,
      name: selectedFile.name,
      type: uploadType,
      fileType: selectedFile.name.split('.').pop()?.toLowerCase() || 'unknown',
      size: selectedFile.size,
      uploadDate: new Date().toLocaleDateString(),
      url: URL.createObjectURL(selectedFile) // Create Blob URL for current session
    };

    const updatedDocs = [...profile.documents, newDoc];
    const updatedProfile = { ...profile, documents: updatedDocs };

    setProfile(updatedProfile);
    saveProfile(updatedProfile);
    setSelectedFile(null);
  };

  const handleDelete = (docId: string) => {
    if (!profile) return;
    const updatedDocs = profile.documents.filter(d => d.id !== docId);
    const updatedProfile = { ...profile, documents: updatedDocs };
    setProfile(updatedProfile);
    saveProfile(updatedProfile);
    if (previewDoc?.id === docId) setPreviewDoc(null);
  };

  if (!profile) return <div>Loading...</div>;

  return (
    <div className="space-y-6">
      <div>
         <h1 className="text-2xl font-bold text-gray-900">Documents</h1>
         <p className="text-gray-500">Upload and manage your resume, certificates, and project files.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Upload Section */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 h-fit">
          <h3 className="font-semibold text-gray-800 mb-4">Upload New Document</h3>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Document Type</label>
              <select 
                className="w-full border-gray-300 rounded-lg shadow-sm p-2 border"
                value={uploadType}
                onChange={(e) => setUploadType(e.target.value as any)}
              >
                <option value="Resume">Resume</option>
                <option value="Certificate">Certificate</option>
                <option value="Project">Project Document</option>
                <option value="Internship">Internship Proof</option>
                <option value="Other">Other</option>
              </select>
            </div>

            <div className="border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:bg-gray-50 transition-colors">
              <input 
                type="file" 
                id="file-upload" 
                className="hidden" 
                onChange={handleFileChange}
                accept=".pdf,.doc,.docx,.jpg,.jpeg,.png"
              />
              <label htmlFor="file-upload" className="cursor-pointer">
                <Upload className="mx-auto h-8 w-8 text-gray-400 mb-2" />
                <p className="text-sm text-gray-600 font-medium">Click to upload file</p>
                <p className="text-xs text-gray-400 mt-1">PDF, DOCX, JPG, PNG (Max 5MB)</p>
              </label>
            </div>

            {selectedFile && (
              <div className="bg-purple-50 p-3 rounded-lg flex items-center justify-between">
                <div className="text-sm truncate max-w-[150px]">{selectedFile.name}</div>
                <button onClick={() => setSelectedFile(null)} className="text-red-500 hover:text-red-700">
                  <X className="w-4 h-4" />
                </button>
              </div>
            )}

            <Button 
              className="w-full" 
              disabled={!selectedFile}
              onClick={handleUpload}
            >
              Upload Document
            </Button>
          </div>
        </div>

        {/* List Section */}
        <div className="lg:col-span-2 space-y-4">
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
             <div className="px-6 py-4 border-b bg-gray-50 font-medium text-gray-700">Uploaded Documents</div>
             {profile.documents.length === 0 ? (
               <div className="p-8 text-center text-gray-500">No documents uploaded yet.</div>
             ) : (
               <ul className="divide-y divide-gray-100">
                 {profile.documents.map(doc => (
                   <li key={doc.id} className="p-4 flex items-center justify-between hover:bg-gray-50">
                     <div className="flex items-center gap-3">
                       <div className={`p-2 rounded-lg ${doc.fileType === 'pdf' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'}`}>
                         {['jpg','png','jpeg'].includes(doc.fileType) ? <ImageIcon className="w-5 h-5" /> : <FileText className="w-5 h-5" />}
                       </div>
                       <div>
                         <p className="font-medium text-gray-900">{doc.name}</p>
                         <p className="text-xs text-gray-500">{doc.type} • {formatBytes(doc.size)} • {doc.uploadDate}</p>
                       </div>
                     </div>
                     <div className="flex items-center gap-2">
                       <Button variant="ghost" size="sm" onClick={() => setPreviewDoc(doc)}>
                         <Eye className="w-4 h-4 text-gray-500" />
                       </Button>
                       <Button variant="ghost" size="sm" onClick={() => handleDelete(doc.id)}>
                         <Trash2 className="w-4 h-4 text-red-500" />
                       </Button>
                     </div>
                   </li>
                 ))}
               </ul>
             )}
          </div>

          {/* Preview Section */}
          {previewDoc && (
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden scroll-mt-6" id="preview-area">
              <div className="px-6 py-4 border-b bg-gray-50 flex justify-between items-center">
                <h3 className="font-medium text-gray-700">Preview: {previewDoc.name}</h3>
                <button onClick={() => setPreviewDoc(null)} className="text-gray-400 hover:text-gray-600">
                  <X className="w-5 h-5" />
                </button>
              </div>
              <div className="p-4 bg-gray-100 min-h-[400px] flex items-center justify-center">
                {['jpg', 'png', 'jpeg'].includes(previewDoc.fileType) ? (
                  <img src={previewDoc.url} alt="Preview" className="max-w-full max-h-[600px] object-contain shadow-lg" />
                ) : previewDoc.fileType === 'pdf' ? (
                  <iframe 
                    src={previewDoc.url} 
                    className="w-full h-[600px] border rounded shadow-lg bg-white" 
                    title="PDF Preview"
                  />
                ) : (
                  <div className="text-center text-gray-500">
                    <FileText className="w-16 h-16 mx-auto mb-4 opacity-50" />
                    <p>Preview not available for this file type.</p>
                    <a href={previewDoc.url} download={previewDoc.name} className="text-purple-600 underline mt-2 block">Download to view</a>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Documents;

import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../../App';
import { getProfileByRollNo, saveProfile } from '../../services/storage';
import { StudentProfile, Education, Project, Skill } from '../../types';
import { Button } from '../../components/ui/Button';
import { Input, Select } from '../../components/ui/Input';
import { Plus, Trash2, Code, BookOpen, Layers } from 'lucide-react';

const EducationPage: React.FC = () => {
  const { user } = useContext(AuthContext);
  const [profile, setProfile] = useState<StudentProfile | null>(null);

  // Form States
  const [newEdu, setNewEdu] = useState<Partial<Education>>({ level: 'UG' });
  const [newSkill, setNewSkill] = useState('');
  const [newProject, setNewProject] = useState<Partial<Project>>({});

  useEffect(() => {
    if (user) {
      const data = getProfileByRollNo(user.username);
      if (data) setProfile(data);
    }
  }, [user]);

  const save = (updatedProfile: StudentProfile) => {
    setProfile(updatedProfile);
    saveProfile(updatedProfile);
  };

  // Education Handlers
  const addEducation = () => {
    if (!profile || !newEdu.institution || !newEdu.year) return;
    const edu: Education = {
      id: `edu-${Date.now()}`,
      level: newEdu.level as any,
      institution: newEdu.institution,
      year: newEdu.year,
      percentage: newEdu.percentage || ''
    };
    save({ ...profile, education: [...profile.education, edu] });
    setNewEdu({ level: 'UG', institution: '', year: '', percentage: '' });
  };

  const removeEducation = (id: string) => {
    if (!profile) return;
    save({ ...profile, education: profile.education.filter(e => e.id !== id) });
  };

  // Skill Handlers
  const addSkill = () => {
    if (!profile || !newSkill.trim()) return;
    const skill: Skill = {
      id: `skill-${Date.now()}`,
      name: newSkill,
      type: 'Technical' // Simplification
    };
    save({ ...profile, skills: [...profile.skills, skill] });
    setNewSkill('');
  };

  const removeSkill = (id: string) => {
    if (!profile) return;
    save({ ...profile, skills: profile.skills.filter(s => s.id !== id) });
  };

  // Project Handlers
  const addProject = () => {
    if (!profile || !newProject.title) return;
    const proj: Project = {
      id: `proj-${Date.now()}`,
      title: newProject.title,
      description: newProject.description || '',
      techStack: newProject.techStack || '',
      link: newProject.link || ''
    };
    save({ ...profile, projects: [...profile.projects, proj] });
    setNewProject({ title: '', description: '', techStack: '', link: '' });
  };

  const removeProject = (id: string) => {
    if (!profile) return;
    save({ ...profile, projects: profile.projects.filter(p => p.id !== id) });
  };

  if (!profile) return <div>Loading...</div>;

  return (
    <div className="space-y-8">
      <div>
         <h1 className="text-2xl font-bold text-gray-900">Education & Skills</h1>
         <p className="text-gray-500">Manage your academic details and technical competencies.</p>
      </div>

      {/* Education Section */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <h2 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
          <BookOpen className="w-5 h-5 text-purple-600" /> Academic History
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-5 gap-4 mb-4 bg-gray-50 p-4 rounded-lg">
           <div className="md:col-span-1">
             <Select 
               options={[{value:'10th', label:'10th'},{value:'12th', label:'12th'},{value:'UG', label:'Undergraduate'},{value:'PG', label:'Postgraduate'}]} 
               value={newEdu.level}
               onChange={e => setNewEdu({...newEdu, level: e.target.value as any})}
               className="bg-white"
             />
           </div>
           <div className="md:col-span-2">
             <Input placeholder="Institution Name" value={newEdu.institution || ''} onChange={e => setNewEdu({...newEdu, institution: e.target.value})} className="bg-white" />
           </div>
           <div className="md:col-span-1">
             <Input placeholder="Year" value={newEdu.year || ''} onChange={e => setNewEdu({...newEdu, year: e.target.value})} className="bg-white" />
           </div>
           <div className="md:col-span-1 flex gap-2">
             <Input placeholder="%" value={newEdu.percentage || ''} onChange={e => setNewEdu({...newEdu, percentage: e.target.value})} className="bg-white" />
             <Button size="sm" onClick={addEducation}><Plus /></Button>
           </div>
        </div>

        <div className="space-y-3">
          {profile.education.map(edu => (
            <div key={edu.id} className="flex justify-between items-center p-3 border rounded-lg hover:bg-gray-50">
              <div>
                <p className="font-semibold text-gray-800">{edu.level} - {edu.institution}</p>
                <p className="text-sm text-gray-600">Passed: {edu.year} • Score: {edu.percentage}%</p>
              </div>
              <button onClick={() => removeEducation(edu.id)} className="text-red-500 hover:text-red-700 p-2"><Trash2 className="w-4 h-4" /></button>
            </div>
          ))}
          {profile.education.length === 0 && <p className="text-center text-gray-400 py-4">No education details added.</p>}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Skills Section */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 h-fit">
          <h2 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
            <Code className="w-5 h-5 text-purple-600" /> Skills
          </h2>
          <div className="flex gap-2 mb-4">
            <Input 
              placeholder="Add a skill (e.g. React, Python)" 
              value={newSkill} 
              onChange={e => setNewSkill(e.target.value)}
              onKeyPress={e => e.key === 'Enter' && addSkill()}
            />
            <Button onClick={addSkill}>Add</Button>
          </div>
          <div className="flex flex-wrap gap-2">
            {profile.skills.map(skill => (
              <span key={skill.id} className="inline-flex items-center px-3 py-1 rounded-full text-sm font-medium bg-purple-100 text-purple-800">
                {skill.name}
                <button onClick={() => removeSkill(skill.id)} className="ml-2 text-purple-600 hover:text-purple-900"><XIcon /></button>
              </span>
            ))}
            {profile.skills.length === 0 && <p className="text-gray-400">No skills added.</p>}
          </div>
        </div>

        {/* Projects Section */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <h2 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
            <Layers className="w-5 h-5 text-purple-600" /> Projects
          </h2>
          <div className="bg-gray-50 p-4 rounded-lg mb-4 space-y-3">
            <Input placeholder="Project Title" value={newProject.title || ''} onChange={e => setNewProject({...newProject, title: e.target.value})} className="bg-white" />
            <Input placeholder="Tech Stack (comma separated)" value={newProject.techStack || ''} onChange={e => setNewProject({...newProject, techStack: e.target.value})} className="bg-white" />
            <Input placeholder="Description" value={newProject.description || ''} onChange={e => setNewProject({...newProject, description: e.target.value})} className="bg-white" />
            <Button onClick={addProject} className="w-full">Add Project</Button>
          </div>

          <div className="space-y-4">
             {profile.projects.map(proj => (
               <div key={proj.id} className="p-3 border rounded-lg">
                 <div className="flex justify-between items-start">
                   <h4 className="font-semibold text-gray-800">{proj.title}</h4>
                   <button onClick={() => removeProject(proj.id)} className="text-red-500"><Trash2 className="w-4 h-4" /></button>
                 </div>
                 <p className="text-xs text-purple-600 mb-1">{proj.techStack}</p>
                 <p className="text-sm text-gray-600">{proj.description}</p>
               </div>
             ))}
