import { StudentProfile, User, Role, Notification } from '../types';

// Mock Data Keys
const USERS_KEY = 'uniprofile_users';
const PROFILES_KEY = 'uniprofile_profiles';
const NOTIFICATIONS_KEY = 'uniprofile_notifications';

// Initialize Admin if not exists
const initStorage = () => {
  const users = localStorage.getItem(USERS_KEY);
  if (!users) {
    const adminUser: User = {
      id: 'admin-1',
      username: 'admin',
      role: Role.ADMIN,
      name: 'College Admin'
    };
    localStorage.setItem(USERS_KEY, JSON.stringify([adminUser]));
  }
};

initStorage();

export const getUsers = (): User[] => {
  return JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
};

export const saveUser = (user: User) => {
  const users = getUsers();
  users.push(user);
  localStorage.setItem(USERS_KEY, JSON.stringify(users));
};

export const getProfiles = (): StudentProfile[] => {
  return JSON.parse(localStorage.getItem(PROFILES_KEY) || '[]');
};

export const getProfileByRollNo = (rollNo: string): StudentProfile | undefined => {
  const profiles = getProfiles();
  return profiles.find(p => p.rollNumber === rollNo);
};

export const saveProfile = (profile: StudentProfile) => {
  const profiles = getProfiles();
  const index = profiles.findIndex(p => p.id === profile.id);

  if (index >= 0) {
    profiles[index] = profile;
  } else {
    profiles.push(profile);
  }

  localStorage.setItem(PROFILES_KEY, JSON.stringify(profiles));
};

// Notification Services
export const getNotifications = (userId: string): Notification[] => {
  const all = JSON.parse(localStorage.getItem(NOTIFICATIONS_KEY) || '[]');
  return all.filter((n: Notification) => n.userId === userId).sort((a: Notification, b: Notification) => 
    new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
  );
};

export const sendNotification = (notification: Omit<Notification, 'id' | 'timestamp' | 'isRead'>) => {
  const all = JSON.parse(localStorage.getItem(NOTIFICATIONS_KEY) || '[]');
  const newNotification: Notification = {
    ...notification,
    id: `notif-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
    timestamp: new Date().toISOString(),
    isRead: false
  };
  all.push(newNotification);
  localStorage.setItem(NOTIFICATIONS_KEY, JSON.stringify(all));
};

export const markNotificationRead = (id: string) => {
  const all = JSON.parse(localStorage.getItem(NOTIFICATIONS_KEY) || '[]');
  const index = all.findIndex((n: Notification) => n.id === id);
  if (index >= 0) {
    all[index].isRead = true;
    localStorage.setItem(NOTIFICATIONS_KEY, JSON.stringify(all));
  }
};

export const markAllNotificationsRead = (userId: string) => {
  const all = JSON.parse(localStorage.getItem(NOTIFICATIONS_KEY) || '[]');
  const updated = all.map((n: Notification) => n.userId === userId ? { ...n, isRead: true } : n);
  localStorage.setItem(NOTIFICATIONS_KEY, JSON.stringify(updated));
};

export const broadcastMessage = (
  title: string, 
  message: string, 
  filters?: { department?: string; year?: string }
) => {
  const profiles = getProfiles();
  const targets = profiles.filter(p => {
    if (filters?.department && p.department !== filters.department) return false;
    if (filters?.year && p.year !== filters.year) return false;
    return true;
  });

  const allNotifications = JSON.parse(localStorage.getItem(NOTIFICATIONS_KEY) || '[]');

  targets.forEach(p => {
    allNotifications.push({
      id: `notif-${Date.now()}-${p.userId}`,
      userId: p.userId, // Using userId (which is essentially id in our mock)
      title,
      message,
      type: 'INFO',
      timestamp: new Date().toISOString(),
      isRead: false
    });
  });

  localStorage.setItem(NOTIFICATIONS_KEY, JSON.stringify(allNotifications));
  return targets.length;
};

// File handling helper (Mock)
export const formatBytes = (bytes: number, decimals = 2) => {
  if (bytes === 0) return '0 Bytes';
  const k = 1024;
  const dm = decimals < 0 ? 0 : decimals;
  const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
};

