import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../../App';
import { getProfileByRollNo, saveProfile, formatBytes } from '../../services/storage';
import { StudentProfile, Document } from '../../types';
import { Button } from '../../components/ui/Button';
import { Upload, Trash2, Eye, FileText, Image as ImageIcon, X, CheckCircle, XCircle, Clock, Info } from 'lucide-react';

const Documents: React.FC = () => {
  const { user } = useContext(AuthContext);
  const [profile, setProfile] = useState<StudentProfile | null>(null);
  const [uploadType, setUploadType] = useState<Document['type']>('Resume');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewDoc, setPreviewDoc] = useState<Document | null>(null);

  useEffect(() => {
    if (user) {
      const data = getProfileByRollNo(user.username);
      if (data) setProfile(data);
    }
  }, [user]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      // Validation: Check size (5MB limit for mock) and type
      if (file.size > 5 * 1024 * 1024) {
        alert("File too large. Max 5MB.");
        return;
      }
      setSelectedFile(file);
    }
  };

  const handleUpload = () => {
    if (!selectedFile || !profile) return;

    const newDoc: Document = {
      id: `doc-${Date.now()}`,
      name: selectedFile.name,
      type: uploadType,
      fileType: selectedFile.name.split('.').pop()?.toLowerCase() || 'unknown',
      size: selectedFile.size,
      uploadDate: new Date().toLocaleDateString(),
      url: URL.createObjectURL(selectedFile), // Create Blob URL for current session
      status: 'Pending'
    };

    const updatedDocs = [...profile.documents, newDoc];
    const updatedProfile = { ...profile, documents: updatedDocs };

    setProfile(updatedProfile);
    saveProfile(updatedProfile);
    setSelectedFile(null);
  };

  const handleDelete = (docId: string) => {
    if (!profile) return;
    const updatedDocs = profile.documents.filter(d => d.id !== docId);
    const updatedProfile = { ...profile, documents: updatedDocs };
    setProfile(updatedProfile);
    saveProfile(updatedProfile);
    if (previewDoc?.id === docId) setPreviewDoc(null);
  };

  const getStatusBadge = (doc: Document) => {
    switch (doc.status) {
      case 'Approved':
        return (
          <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-green-100 text-green-800">
            <CheckCircle className="w-3 h-3 mr-1" /> Approved
          </span>
        );
      case 'Rejected':
        return (
          <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-red-100 text-red-800">
            <XCircle className="w-3 h-3 mr-1" /> Rejected
          </span>
        );
      default:
        return (
          <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-yellow-100 text-yellow-800">
            <Clock className="w-3 h-3 mr-1" /> Pending
          </span>
        );
    }
  };

  if (!profile) return <div>Loading...</div>;

  return (
    <div className="space-y-6">
      <div>
         <h1 className="text-2xl font-bold text-gray-900">Documents</h1>
         <p className="text-gray-500">Upload and manage your resume, certificates, and project files.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Upload Section */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 h-fit">
          <h3 className="font-semibold text-gray-800 mb-4">Upload New Document</h3>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Document Type</label>
              <select 
                className="w-full border-gray-300 rounded-lg shadow-sm p-2 border"
                value={uploadType}
                onChange={(e) => setUploadType(e.target.value as any)}
              >
                <option value="Resume">Resume</option>
                <option value="Certificate">Certificate</option>
                <option value="Project">Project Document</option>
                <option value="Internship">Internship Proof</option>
                <option value="Other">Other</option>
              </select>
            </div>

            <div className="border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:bg-gray-50 transition-colors">
              <input 
                type="file" 
                id="file-upload" 
                className="hidden" 
                onChange={handleFileChange}
                accept=".pdf,.doc,.docx,.jpg,.jpeg,.png"
              />
              <label htmlFor="file-upload" className="cursor-pointer">
                <Upload className="mx-auto h-8 w-8 text-gray-400 mb-2" />
                <p className="text-sm text-gray-600 font-medium">Click to upload file</p>
                <p className="text-xs text-gray-400 mt-1">PDF, DOCX, JPG, PNG (Max 5MB)</p>
              </label>
            </div>

            {selectedFile && (
              <div className="bg-purple-50 p-3 rounded-lg flex items-center justify-between">
                <div className="text-sm truncate max-w-[150px]">{selectedFile.name}</div>
                <button onClick={() => setSelectedFile(null)} className="text-red-500 hover:text-red-700">
                  <X className="w-4 h-4" />
                </button>
              </div>
            )}

            <Button 
              className="w-full" 
              disabled={!selectedFile}
              onClick={handleUpload}
            >
              Upload Document
            </Button>
          </div>
        </div>

        {/* List Section */}
        <div className="lg:col-span-2 space-y-4">
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
             <div className="px-6 py-4 border-b bg-gray-50 font-medium text-gray-700">Uploaded Documents</div>
             {profile.documents.length === 0 ? (
               <div className="p-8 text-center text-gray-500">No documents uploaded yet.</div>
             ) : (
               <ul className="divide-y divide-gray-100">
                 {profile.documents.map(doc => (
                   <li key={doc.id} className="p-4 flex flex-col sm:flex-row sm:items-center justify-between hover:bg-gray-50 gap-4">
                     <div className="flex items-center gap-3">
                       <div className={`p-2 rounded-lg ${doc.fileType === 'pdf' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'}`}>
                         {['jpg','png','jpeg'].includes(doc.fileType) ? <ImageIcon className="w-5 h-5" /> : <FileText className="w-5 h-5" />}
                       </div>
                       <div>
                         <div className="flex items-center gap-2">
                           <p className="font-medium text-gray-900">{doc.name}</p>
                           {getStatusBadge(doc)}
                         </div>
                         <p className="text-xs text-gray-500">{doc.type} • {formatBytes(doc.size)} • {doc.uploadDate}</p>
                         {doc.status === 'Rejected' && doc.feedback && (
                           <div className="text-xs text-red-600 mt-1 flex items-center gap-1">
                             <Info className="w-3 h-3" /> {doc.feedback}
                           </div>
                         )}
                       </div>
                     </div>
                     <div className="flex items-center gap-2 self-end sm:self-center">
                       <Button variant="ghost" size="sm" onClick={() => setPreviewDoc(doc)}>
                         <Eye className="w-4 h-4 text-gray-500" />
                       </Button>
                       <Button variant="ghost" size="sm" onClick={() => handleDelete(doc.id)}>
                         <Trash2 className="w-4 h-4 text-red-500" />
                       </Button>
                     </div>
                   </li>
                 ))}
               </ul>
             )}
          </div>

          {/* Preview Section */}
          {previewDoc && (
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden scroll-mt-6" id="preview-area">
              <div className="px-6 py-4 border-b bg-gray-50 flex justify-between items-center">
                <div className="flex items-center gap-3">
                  <h3 className="font-medium text-gray-700">Preview: {previewDoc.name}</h3>
                  {getStatusBadge(previewDoc)}
                </div>
                <button onClick={() => setPreviewDoc(null)} className="text-gray-400 hover:text-gray-600">
                  <X className="w-5 h-5" />
                </button>
              </div>
              <div className="p-4 bg-gray-100 min-h-[400px] flex items-center justify-center">
                {['jpg', 'png', 'jpeg'].includes(previewDoc.fileType) ? (
                  <img src={previewDoc.url} alt="Preview" className="max-w-full max-h-[600px] object-contain shadow-lg" />
                ) : previewDoc.fileType === 'pdf' ? (
                  <iframe 
                    src={previewDoc.url} 
                    className="w-full h-[600px] border rounded shadow-lg bg-white" 
                    title="PDF Preview"
                  />
                ) : (
                  <div className="text-center text-gray-500">
                    <FileText className="w-16 h-16 mx-auto mb-4 opacity-50" />
                    <p>Preview not available for this file type.</p>
                    <a href={previewDoc.url} download={previewDoc.name} className="text-purple-600 underline mt-2 block">Download to view</a>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Documents;

import React, { useState, useContext } from 'react';
import { AuthContext } from '../../App';
import { getProfiles, saveProfile, broadcastMessage, sendNotification } from '../../services/storage';
import { StudentProfile } from '../../types';
import { Button } from '../../components/ui/Button';
import { Input, Select } from '../../components/ui/Input';
import { Search, Eye, Download, LogOut, Shield, Megaphone, Check, X, Bell } from 'lucide-react';

const AdminDashboard: React.FC = () => {
  const { logout } = useContext(AuthContext);
  const [profiles, setProfiles] = useState<StudentProfile[]>(getProfiles());
  const [searchTerm, setSearchTerm] = useState('');
  const [viewProfile, setViewProfile] = useState<StudentProfile | null>(null);

  // Broadcast State
  const [showBroadcastModal, setShowBroadcastModal] = useState(false);
  const [broadcastData, setBroadcastData] = useState({ title: '', message: '', targetDept: '', targetYear: '' });
  const [broadcastStatus, setBroadcastStatus] = useState('');

  const handleSearch = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSearchTerm(e.target.value.toLowerCase());
  };

  const filteredProfiles = profiles.filter(p => 
    p.fullName.toLowerCase().includes(searchTerm) || 
    p.rollNumber.toLowerCase().includes(searchTerm) ||
    p.department.toLowerCase().includes(searchTerm)
  );

  const generateReport = () => {
    const headers = ['Roll No', 'Name', 'Department', 'Email', 'Phone', 'Year', 'Docs Uploaded'];
    const rows = filteredProfiles.map(p => [
      p.rollNumber, 
      p.fullName, 
      p.department, 
      p.email, 
      p.phone, 
      p.year,
      p.documents.length.toString()
    ]);
    const csvContent = "data:text/csv;charset=utf-8," 
      + headers.join(",") + "\n" 
      + rows.map(e => e.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "student_report.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleBroadcastSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const count = broadcastMessage(
      broadcastData.title, 
      broadcastData.message, 
      {
        department: broadcastData.targetDept || undefined,
        year: broadcastData.targetYear || undefined
      }
    );
    setBroadcastStatus(`Announcement sent to ${count} students.`);
    setBroadcastData({ title: '', message: '', targetDept: '', targetYear: '' });
    setTimeout(() => {
      setShowBroadcastModal(false);
      setBroadcastStatus('');
    }, 2000);
  };

  const updateDocumentStatus = (docId: string, status: 'Approved' | 'Rejected', feedback?: string) => {
    if (!viewProfile) return;

    // Update local profile state
    const updatedDocs = viewProfile.documents.map(d => 
      d.id === docId ? { ...d, status, feedback } : d
    );
    const updatedProfile = { ...viewProfile, documents: updatedDocs };

    // Update master state and storage
    const updatedProfiles = profiles.map(p => p.id === viewProfile.id ? updatedProfile : p);
    setProfiles(updatedProfiles);
    setViewProfile(updatedProfile);
    saveProfile(updatedProfile);

    // Send Notification
    sendNotification({
      userId: viewProfile.userId,
      type: status === 'Approved' ? 'SUCCESS' : 'ERROR',
      title: `Document ${status}`,
      message: status === 'Approved' 
        ? `Your document has been approved.` 
        : `Your document was rejected. Reason: ${feedback || 'Does not meet requirements.'}`
    });
  };

  return (
    <div className="min-h-screen bg-gray-100">
      {/* Admin Header */}
      <header className="bg-purple-800 text-white shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <Shield className="h-8 w-8" />
            <h1 className="text-xl font-bold">Admin Portal</h1>
          </div>
          <div className="flex gap-4">
            <Button variant="secondary" size="sm" onClick={() => setShowBroadcastModal(true)} className="text-purple-800 border-white bg-white hover:bg-purple-50">
              <Megaphone className="w-4 h-4 mr-2" /> Broadcast
            </Button>
            <Button variant="secondary" size="sm" onClick={logout} className="text-purple-800 bg-white border-white hover:bg-purple-50">
              <LogOut className="w-4 h-4 mr-2" /> Logout
            </Button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {!viewProfile ? (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-center gap-4 bg-white p-4 rounded-xl shadow-sm border border-purple-100">
              <div className="w-full md:w-96 relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
                <Input 
                  placeholder="Search students..." 
                  className="pl-10" 
                  value={searchTerm}
                  onChange={handleSearch}
                />
              </div>
              <Button onClick={generateReport} variant="outline">
                <Download className="w-4 h-4 mr-2" /> Export Report
              </Button>
            </div>

            <div className="bg-white rounded-xl shadow-sm overflow-hidden border border-gray-200">
              <div className="overflow-x-auto">
                <table className="min-w-full divide-y divide-gray-200">
                  <thead className="bg-gray-50">
                    <tr>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Student</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Dept</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Batch</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                      <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="bg-white divide-y divide-gray-200">
                    {filteredProfiles.map((student) => (
                      <tr key={student.id} className="hover:bg-gray-50 transition-colors">
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="flex items-center">
                            <div className="h-10 w-10 rounded-full bg-purple-100 flex items-center justify-center text-purple-700 font-bold">
                              {student.fullName.charAt(0)}
                            </div>
                            <div className="ml-4">
                              <div className="text-sm font-medium text-gray-900">{student.fullName}</div>
                              <div className="text-sm text-gray-500">{student.rollNumber}</div>
                            </div>
                          </div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{student.department}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">Year {student.year}</td>
                        <td className="px-6 py-4 whitespace-nowrap">
                           {student.documents.some(d => d.status === 'Pending') ? (
                             <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-yellow-100 text-yellow-800">
                               Action Needed
                             </span>
                           ) : (
                             <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-green-100 text-green-800">
                               Up to date
                             </span>
                           )}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                          <button 
                            onClick={() => setViewProfile(student)}
                            className="text-purple-600 hover:text-purple-900 font-medium"
                          >
                            View Details
                          </button>
                        </td>
                      </tr>
                    ))}
                    {filteredProfiles.length === 0 && (
                      <tr>
                        <td colSpan={5} className="px-6 py-12 text-center text-gray-500">
                          No students found matching your search.
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <Button variant="secondary" onClick={() => setViewProfile(null)}>
              ← Back to List
            </Button>

            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-8">
              <div className="flex justify-between items-start mb-6">
                <div>
                   <h2 className="text-2xl font-bold text-gray-900">{viewProfile.fullName}</h2>
                   <p className="text-gray-500">{viewProfile.rollNumber} • {viewProfile.department}</p>
                </div>
                <div className="text-right">
                   <p className="text-sm text-gray-500">Year {viewProfile.year}</p>
                </div>
              </div>

