import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { User, Role } from './types';
import Login from './pages/Login';
import Register from './pages/Register';
import ForgotPassword from './pages/ForgotPassword';
import AdminDashboard from './pages/admin/Dashboard';
import StudentLayout from './pages/student/StudentLayout';
import StudentProfile from './pages/student/Profile';
import StudentDocuments from './pages/student/Documents';
import StudentEducation from './pages/student/Education';
import StudentResume from './pages/student/Resume';

export const AuthContext = React.createContext<{
  user: User | null;
  login: (user: User) => void;
  logout: () => void;
}>({
  user: null,
  login: () => {},
  logout: () => {},
});

const ProtectedRoute = ({ children, allowedRoles }: { children?: React.ReactNode; allowedRoles: Role[] }) => {
  const { user } = React.useContext(AuthContext);
  const location = useLocation();

  if (!user) {
    return <Navigate to="/login" state={{ from: location }} replace />;
  }
  if (!user.isActive) {
    // In a real app, handle disabled account better
    return <Navigate to="/login" replace />;
  }
  if (!allowedRoles.includes(user.role)) {
    return <Navigate to="/" replace />;
  }
  return <>{children}</>;
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const session = localStorage.getItem('profilehub_session');
    if (session) {
      setUser(JSON.parse(session));
    }
    setLoading(false);
  }, []);

  const login = (newUser: User) => {
    setUser(newUser);
    localStorage.setItem('profilehub_session', JSON.stringify(newUser));
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('profilehub_session');
  };

  if (loading) return <div className="h-screen w-full flex items-center justify-center text-blue-800 font-bold">Loading ProfileHub...</div>;

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      <HashRouter>
        <Routes>
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route path="/forgot-password" element={<ForgotPassword />} />

          <Route path="/admin" element={
              <ProtectedRoute allowedRoles={[Role.ADMIN]}>
                <AdminDashboard />
              </ProtectedRoute>
          } />

          <Route path="/student" element={
              <ProtectedRoute allowedRoles={[Role.STUDENT]}>
                <StudentLayout />
              </ProtectedRoute>
          }>
            <Route index element={<Navigate to="/student/profile" replace />} />
            <Route path="profile" element={<StudentProfile />} />
            <Route path="documents" element={<StudentDocuments />} />
            <Route path="education" element={<StudentEducation />} />
            <Route path="resume" element={<StudentResume />} />
          </Route>

          <Route path="/" element={<Navigate to={user ? (user.role === Role.ADMIN ? '/admin' : '/student/profile') : '/login'} replace />} />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </HashRouter>
    </AuthContext.Provider>
  );
};

export default App;

