import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Input } from '../components/ui/Input';
import { Button } from '../components/ui/Button';
import { getUsers, sendOTP, savePassword } from '../services/storage';
import { ArrowLeft, KeyRound, Mail } from 'lucide-react';

const ForgotPassword: React.FC = () => {
  const navigate = useNavigate();
  const [step, setStep] = useState(1); // 1: Email, 2: OTP, 3: New Pass
  const [email, setEmail] = useState('');
  const [userId, setUserId] = useState('');
  const [otp, setOtp] = useState('');
  const [sentOtp, setSentOtp] = useState('');
  const [newPass, setNewPass] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSendOTP = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    // Find user by email or username
    const users = getUsers();
    // For mock, we check against local profiles to find email match
    const profiles = JSON.parse(localStorage.getItem('profilehub_profiles') || '[]');
    const profile = profiles.find((p: any) => p.email === email || p.username === email);

    if (profile) {
      setUserId(profile.userId);
      const generatedOtp = await sendOTP(profile.email);
      setSentOtp(generatedOtp);
      setStep(2);
    } else {
      setError('No user found with this email/username.');
    }
    setLoading(false);
  };

  const handleVerifyOTP = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp === sentOtp) {
      setStep(3);
    } else {
      setError('Invalid OTP');
    }
  };

  const handleResetPass = (e: React.FormEvent) => {
    e.preventDefault();
    if (newPass.length < 6) {
      setError('Password must be at least 6 characters');
      return;
    }
    savePassword(userId, newPass);
    alert('Password reset successful! Please login.');
    navigate('/login');
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-100 py-12 px-4">
      <div className="max-w-md w-full bg-white p-8 rounded-2xl shadow-xl border-t-4 border-blue-900">
        <Link to="/login" className="flex items-center text-sm text-gray-500 hover:text-blue-800 mb-6">
          <ArrowLeft className="w-4 h-4 mr-1" /> Back to Login
        </Link>

        <div className="text-center mb-8">
           <div className="mx-auto h-12 w-12 bg-blue-50 rounded-full flex items-center justify-center mb-4">
             <KeyRound className="w-6 h-6 text-blue-800" />
           </div>
           <h2 className="text-2xl font-bold text-gray-900">Reset Password</h2>
           <p className="text-gray-500 text-sm mt-1">
             {step === 1 && "Enter your college email or username"}
             {step === 2 && "Enter the OTP sent to your email"}
             {step === 3 && "Create a new strong password"}
           </p>
        </div>

        {error && <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm mb-4 text-center">{error}</div>}

        {step === 1 && (
          <form onSubmit={handleSendOTP} className="space-y-4">
            <Input 
              label="Email or Username" 
              placeholder="username or email@bitsathy.ac.in" 
              value={email} 
              onChange={e => setEmail(e.target.value)} 
              required 
            />
            <Button type="submit" className="w-full" isLoading={loading}>Send OTP</Button>
          </form>
        )}

        {step === 2 && (
          <form onSubmit={handleVerifyOTP} className="space-y-4">
            <Input 
              label="Enter OTP" 
              placeholder="XXXX" 
              value={otp} 
              onChange={e => setOtp(e.target.value)} 
              required 
            />
            <Button type="submit" className="w-full">Verify OTP</Button>
          </form>
        )}

        {step === 3 && (
          <form onSubmit={handleResetPass} className="space-y-4">
            <Input 
              label="New Password" 
              type="password" 
              placeholder="••••••" 
              value={newPass} 
              onChange={e => setNewPass(e.target.value)} 
              required 
            />
            <Button type="submit" className="w-full">Reset Password</Button>
          </form>
        )}
      </div>
    </div>
  );
};

