import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../../App';
import { getProfileByUsername, saveProfile, formatBytes } from '../../services/storage';
import { StudentProfile, Document } from '../../types';
import { Button } from '../../components/ui/Button';
import { Upload, Trash2, Eye, FileText, Image as ImageIcon, X, CheckCircle, XCircle, Clock, Info } from 'lucide-react';

const Documents: React.FC = () => {
  const { user } = useContext(AuthContext);
  const [profile, setProfile] = useState<StudentProfile | null>(null);
  const [uploadType, setUploadType] = useState<Document['type']>('Resume');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewDoc, setPreviewDoc] = useState<Document | null>(null);

  useEffect(() => {
    if (user) {
      const data = getProfileByUsername(user.username);
      if (data) setProfile(data);
    }
  }, [user]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.size > 5 * 1024 * 1024) { alert("Max 5MB"); return; }
      setSelectedFile(file);
    }
  };

  const handleUpload = () => {
    if (!selectedFile || !profile) return;
    const newDoc: Document = {
      id: `doc-${Date.now()}`, name: selectedFile.name, type: uploadType,
      fileType: selectedFile.name.split('.').pop()?.toLowerCase() || 'unknown',
      size: selectedFile.size, uploadDate: new Date().toLocaleDateString(),
      url: URL.createObjectURL(selectedFile), status: 'Pending'
    };
    const updated = { ...profile, documents: [...profile.documents, newDoc] };
    setProfile(updated);
    saveProfile(updated);
    setSelectedFile(null);
  };

  const handleDelete = (docId: string) => {
    if (!profile) return;
    const updated = { ...profile, documents: profile.documents.filter(d => d.id !== docId) };
    setProfile(updated);
    saveProfile(updated);
    if (previewDoc?.id === docId) setPreviewDoc(null);
  };

  if (!profile) return <div>Loading...</div>;

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex justify-between items-end">
        <div>
           <h1 className="text-2xl font-bold text-slate-800">Document Manager</h1>
           <p className="text-slate-500">Upload resumes, certificates, and proofs.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Upload Card */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-fit">
          <h3 className="font-semibold text-slate-800 mb-4 border-b pb-2">Upload New Document</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Document Type</label>
              <select className="w-full border-slate-300 rounded-lg shadow-sm p-2 border"
                value={uploadType} onChange={(e) => setUploadType(e.target.value as any)}>
                <option value="Resume">Resume</option>
                <option value="Certificate">Certificate</option>
                <option value="Project">Project Document</option>
                <option value="Internship">Internship Proof</option>
                <option value="Placement">Placement Related</option>
                <option value="Other">Other</option>
              </select>
            </div>
            <div className="border-2 border-dashed border-slate-300 rounded-lg p-6 text-center hover:bg-slate-50 transition-colors">
              <input type="file" id="file-upload" className="hidden" onChange={handleFileChange} accept=".pdf,.doc,.docx,.jpg,.png" />
              <label htmlFor="file-upload" className="cursor-pointer flex flex-col items-center">
                <Upload className="h-8 w-8 text-blue-500 mb-2" />
                <span className="text-sm font-medium text-slate-600">Click to upload</span>
                <span className="text-xs text-slate-400 mt-1">PDF, JPG, PNG (Max 5MB)</span>
              </label>
            </div>
            {selectedFile && <div className="text-sm bg-blue-50 p-2 rounded text-blue-800 flex justify-between">{selectedFile.name} <X className="w-4 cursor-pointer" onClick={()=>setSelectedFile(null)}/></div>}
            <Button className="w-full" disabled={!selectedFile} onClick={handleUpload}>Upload Document</Button>
          </div>
        </div>

        {/* List */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
             <div className="px-6 py-4 border-b bg-slate-50 font-semibold text-slate-700">Uploaded Documents</div>
             {profile.documents.length === 0 ? <div className="p-8 text-center text-slate-400">No documents yet.</div> : (
               <ul className="divide-y divide-slate-100">
                 {profile.documents.map(doc => (
                   <li key={doc.id} className="p-4 hover:bg-slate-50 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                     <div className="flex items-center gap-4">
                       <div className={`p-3 rounded-lg ${doc.fileType === 'pdf' ? 'bg-red-50 text-red-600' : 'bg-blue-50 text-blue-600'}`}>
                         {['jpg','png','jpeg'].includes(doc.fileType) ? <ImageIcon /> : <FileText />}
                       </div>
                       <div>
                         <div className="flex items-center gap-2">
                           <p className="font-semibold text-slate-800">{doc.name}</p>
                           <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider ${
                             doc.status === 'Approved' ? 'bg-emerald-100 text-emerald-700' :
                             doc.status === 'Rejected' ? 'bg-red-100 text-red-700' : 'bg-amber-100 text-amber-700'
                           }`}>{doc.status}</span>
                         </div>
                         <p className="text-xs text-slate-500 mt-0.5">{doc.type} • {formatBytes(doc.size)} • {doc.uploadDate}</p>
                         {doc.status === 'Rejected' && doc.feedback && (
                           <p className="text-xs text-red-600 mt-1 flex items-center gap-1"><Info className="w-3 h-3"/> {doc.feedback}</p>
                         )}
                       </div>
                     </div>
                     <div className="flex gap-2">
                       <Button variant="ghost" size="sm" onClick={() => setPreviewDoc(doc)}><Eye className="w-4 h-4" /></Button>
                       <Button variant="ghost" size="sm" onClick={() => handleDelete(doc.id)} className="text-red-500 hover:text-red-600"><Trash2 className="w-4 h-4" /></Button>
                     </div>
                   </li>
                 ))}
               </ul>
             )}
        </div>
      </div>

      {/* Preview Modal */}
      {previewDoc && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl max-h-[90vh] flex flex-col overflow-hidden">
            <div className="p-4 border-b flex justify-between items-center bg-slate-50">
              <h3 className="font-bold text-slate-800">{previewDoc.name}</h3>
              <button onClick={() => setPreviewDoc(null)}><X className="w-6 h-6 text-slate-500 hover:text-red-500"/></button>
            </div>
            <div className="flex-1 bg-slate-100 p-4 overflow-auto flex justify-center">
              {['jpg', 'png', 'jpeg'].includes(previewDoc.fileType) ? (
                <img src={previewDoc.url} className="max-w-full object-contain" />
              ) : previewDoc.fileType === 'pdf' ? (
                <iframe src={previewDoc.url} className="w-full h-full min-h-[500px]" />
              ) : <div className="text-center mt-20">Preview not available. <a href={previewDoc.url} download className="text-blue-600 underline">Download</a></div>}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Documents;

