import React, { useState, useContext } from 'react';
import { AuthContext } from '../../App';
import { getProfiles, saveProfile, broadcastMessage, sendNotification, getNotifications } from '../../services/storage';
import { StudentProfile, DEPARTMENTS } from '../../types';
import { Button } from '../../components/ui/Button';
import { Input, Select } from '../../components/ui/Input';
import { Search, Eye, Download, LogOut, Shield, Megaphone, Check, X, BarChart2 } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

const AdminDashboard: React.FC = () => {
  const { logout } = useContext(AuthContext);
  const [profiles, setProfiles] = useState<StudentProfile[]>(getProfiles());
  const [searchTerm, setSearchTerm] = useState('');
  const [deptFilter, setDeptFilter] = useState('');
  const [viewProfile, setViewProfile] = useState<StudentProfile | null>(null);
  const [showBroadcast, setShowBroadcast] = useState(false);
  const [broadcastData, setBroadcastData] = useState({ title: '', message: '', targetDept: '' });

  const filtered = profiles.filter(p => {
    const matchesSearch = p.fullName.toLowerCase().includes(searchTerm.toLowerCase()) || p.username.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesDept = deptFilter ? p.department === deptFilter : true;
    return matchesSearch && matchesDept;
  });

  // Stats
  const stats = {
    total: profiles.length,
    docs: profiles.reduce((acc, p) => acc + p.documents.length, 0),
    pending: profiles.reduce((acc, p) => acc + p.documents.filter(d => d.status === 'Pending').length, 0),
  };

  const chartData = DEPARTMENTS.slice(0, 5).map(dept => ({
    name: dept.split(' ')[0], // Short name
    count: profiles.filter(p => p.department === dept).length
  }));

  const handleDocumentAction = (docId: string, action: 'Approved' | 'Rejected') => {
    if(!viewProfile) return;
    const reason = action === 'Rejected' ? prompt("Enter rejection reason:") : undefined;
    if(action === 'Rejected' && !reason) return;

    const updatedDocs = viewProfile.documents.map(d => d.id === docId ? { ...d, status: action, feedback: reason } : d);
    const updatedProfile = { ...viewProfile, documents: updatedDocs };

    setProfiles(profiles.map(p => p.id === viewProfile.id ? updatedProfile : p));
    setViewProfile(updatedProfile);
    saveProfile(updatedProfile);

    sendNotification({
      userId: viewProfile.userId, type: action === 'Approved' ? 'SUCCESS' : 'ERROR',
      title: `Document ${action}`, message: `Your document was ${action.toLowerCase()}. ${reason || ''}`
    });
  };

  const generateReport = () => {
    const csv = "Username,Name,Department,Phone,Documents,Pending\n" + 
      filtered.map(p => `${p.username},${p.fullName},${p.department},${p.phone},${p.documents.length},${p.documents.filter(d=>d.status==='Pending').length}`).join("\n");
    const link = document.createElement("a");
    link.href = "data:text/csv;charset=utf-8," + encodeURI(csv);
    link.download = "ProfileHub_Report.csv";
    link.click();
  };

  const sendBroadcast = (e: React.FormEvent) => {
    e.preventDefault();
    const count = broadcastMessage(broadcastData.title, broadcastData.message, { department: broadcastData.targetDept || undefined });
    alert(`Sent to ${count} students.`);
    setShowBroadcast(false);
    setBroadcastData({ title: '', message: '', targetDept: '' });
  };

  return (
    <div className="min-h-screen bg-slate-100 font-sans">
      <header className="bg-blue-900 text-white shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">
          <div className="flex items-center gap-2"><Shield className="h-6 w-6" /><h1 className="text-xl font-bold">ProfileHub Admin</h1></div>
          <div className="flex gap-3">
             <Button variant="secondary" size="sm" onClick={() => setShowBroadcast(true)}><Megaphone className="w-4 h-4 mr-2"/> Broadcast</Button>
             <Button variant="danger" size="sm" onClick={logout}><LogOut className="w-4 h-4 mr-2"/> Logout</Button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 py-8">
        {!viewProfile ? (
          <div className="space-y-6">
            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <div className="bg-white p-4 rounded-xl shadow-sm border-l-4 border-blue-600">
                <p className="text-slate-500 text-sm">Total Students</p>
                <p className="text-2xl font-bold text-slate-800">{stats.total}</p>
              </div>
              <div className="bg-white p-4 rounded-xl shadow-sm border-l-4 border-emerald-500">
                <p className="text-slate-500 text-sm">Total Documents</p>
                <p className="text-2xl font-bold text-slate-800">{stats.docs}</p>
              </div>
              <div className="bg-white p-4 rounded-xl shadow-sm border-l-4 border-amber-500">
                <p className="text-slate-500 text-sm">Pending Reviews</p>
                <p className="text-2xl font-bold text-slate-800">{stats.pending}</p>
              </div>
              <div className="bg-white p-4 rounded-xl shadow-sm border-l-4 border-purple-500">
                <p className="text-slate-500 text-sm">Departments</p>
                <p className="text-2xl font-bold text-slate-800">{DEPARTMENTS.length}</p>
              </div>
            </div>

            {/* Filters */}
            <div className="bg-white p-4 rounded-xl shadow-sm flex flex-col md:flex-row gap-4 justify-between items-center">
               <div className="flex gap-2 w-full md:w-2/3">
                 <div className="relative flex-1">
                   <Search className="absolute left-3 top-2.5 text-gray-400 w-5 h-5" />
                   <Input placeholder="Search name or username..." className="pl-10" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                 </div>
                 <select className="border rounded-lg px-2 text-sm max-w-[200px]" value={deptFilter} onChange={e => setDeptFilter(e.target.value)}>
                   <option value="">All Departments</option>
                   {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
                 </select>
               </div>
               <Button onClick={generateReport} variant="outline"><Download className="w-4 h-4 mr-2"/> Export Data</Button>
            </div>

            {/* Table */}
            <div className="bg-white rounded-xl shadow-sm overflow-hidden border border-slate-200">
              <table className="min-w-full divide-y divide-slate-200">
                <thead className="bg-slate-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Student</th>
                    <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Department</th>
                    <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Pending Docs</th>
                    <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase">Action</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {filtered.map(s => (
                    <tr key={s.id} className="hover:bg-slate-50">
                      <td className="px-6 py-4">
                        <div className="flex items-center">
                          <div className="h-8 w-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-700 font-bold mr-3">{s.fullName[0]}</div>
                          <div><div className="text-sm font-medium text-slate-900">{s.fullName}</div><div className="text-xs text-slate-500">{s.username}</div></div>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-sm text-slate-600 truncate max-w-[200px]">{s.department}</td>
                      <td className="px-6 py-4">
                        {s.documents.some(d => d.status === 'Pending') ? <span className="px-2 py-1 bg-amber-100 text-amber-800 text-xs rounded-full font-bold">Action Required</span> : <span className="text-slate-400 text-xs">-</span>}
                      </td>
                      <td className="px-6 py-4 text-right"><Button size="sm" variant="ghost" onClick={() => setViewProfile(s)}>View</Button></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        ) : (
          <div className="space-y-6 animate-fade-in">
             <Button variant="secondary" onClick={() => setViewProfile(null)}>← Back</Button>
             <div className="bg-white rounded-xl shadow-sm border p-8">
                <div className="flex justify-between border-b pb-4 mb-6">
                  <div>
                    <h2 className="text-2xl font-bold text-slate-800">{viewProfile.fullName}</h2>
                    <p className="text-slate-500">{viewProfile.username} • {viewProfile.department}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-sm font-semibold text-slate-600">Completeness Score</p>
                    <div className="text-3xl font-bold text-blue-600">{viewProfile.completenessScore}%</div>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                   <div>
                     <h3 className="font-bold text-slate-800 mb-4">Uploaded Documents</h3>
                     <div className="space-y-3">
                       {viewProfile.documents.map(doc => (
                         <div key={doc.id} className="border p-3 rounded-lg flex justify-between items-center">
                           <div>
                             <p className="font-medium text-sm">{doc.name}</p>
                             <p className="text-xs text-slate-500">{doc.type}</p>
                           </div>
                           <div className="flex items-center gap-2">
                              {doc.status === 'Pending' ? (
                                <>
                                  <button onClick={() => handleDocumentAction(doc.id, 'Approved')} className="p-1 bg-green-100 text-green-700 rounded"><Check className="w-4 h-4"/></button>
                                  <button onClick={() => handleDocumentAction(doc.id, 'Rejected')} className="p-1 bg-red-100 text-red-700 rounded"><X className="w-4 h-4"/></button>
                                </>
                              ) : <span className={`text-xs px-2 py-1 rounded font-bold ${doc.status === 'Approved' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>{doc.status}</span>}
                              <a href={doc.url} target="_blank" className="p-1 hover:bg-slate-100 rounded"><Eye className="w-4 h-4 text-slate-500"/></a>
                           </div>
                         </div>
                       ))}
                       {viewProfile.documents.length === 0 && <p className="text-slate-400 text-sm">No documents.</p>}
                     </div>
                   </div>

                   <div className="bg-slate-50 p-6 rounded-xl h-fit">
                     <h3 className="font-bold text-slate-800 mb-4">Admin Controls</h3>
                     <div className="space-y-2">
                       <Button className="w-full" variant="secondary" onClick={() => alert("Reset Password Link Sent")}>Reset Password</Button>
                       <Button className="w-full" variant="danger">Disable Account</Button>
                     </div>
                   </div>
                </div>
             </div>
          </div>
        )}
      </main>

      {/* Broadcast Modal */}
      {showBroadcast && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden">
             <div className="bg-blue-900 p-4 text-white flex justify-between"><h3 className="font-bold">Broadcast Announcement</h3><button onClick={() => setShowBroadcast(false)}><X/></button></div>
             <form onSubmit={sendBroadcast} className="p-6 space-y-4">
               <Input label="Title" required value={broadcastData.title} onChange={e => setBroadcastData({...broadcastData, title: e.target.value})} />
               <div><label className="text-sm font-semibold">Message</label><textarea className="w-full border rounded-lg p-2 h-24" required value={broadcastData.message} onChange={e => setBroadcastData({...broadcastData, message: e.target.value})}/></div>
               <Select label="Target Dept (Optional)" options={DEPARTMENTS.map(d=>({value:d, label:d}))} value={broadcastData.targetDept} onChange={e=>setBroadcastData({...broadcastData, targetDept: e.target.value})}/>
               <Button type="submit" className="w-full">Send</Button>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

