// --- Core Data Access ---

export const getUsers = (): User[] => JSON.parse(localStorage.getItem(USERS_KEY) || '[]');

export const getProfiles = (): StudentProfile[] => JSON.parse(localStorage.getItem(PROFILES_KEY) || '[]');

export const getProfileByUsername = (username: string): StudentProfile | undefined => {
  return getProfiles().find(p => p.username === username);
};

export const saveUser = (user: User) => {
  const users = getUsers();
  users.push(user);
  localStorage.setItem(USERS_KEY, JSON.stringify(users));
};

export const savePassword = (userId: string, pass: string) => {
    const authDb = JSON.parse(localStorage.getItem(AUTH_KEY) || '{}');
    authDb[userId] = pass;
    localStorage.setItem(AUTH_KEY, JSON.stringify(authDb));
}

export const saveProfile = (profile: StudentProfile) => {
  const profiles = getProfiles();
  // Calculate completeness score before saving
  let score = 0;
  if(profile.fullName) score += 10;
  if(profile.education.length > 0) score += 20;
  if(profile.skills.length > 0) score += 10;
  if(profile.projects.length > 0) score += 20;
  if(profile.documents.find(d => d.type === 'Resume')) score += 20;
  if(profile.profilePhoto) score += 10;
  if(profile.documents.length > 2) score += 10;
  profile.completenessScore = Math.min(score, 100);

  const index = profiles.findIndex(p => p.id === profile.id);
  if (index >= 0) profiles[index] = profile;
  else profiles.push(profile);
  localStorage.setItem(PROFILES_KEY, JSON.stringify(profiles));
  logActivity(profile.userId, "Profile Updated");
};

// --- Notifications ---

export const getNotifications = (userId: string): Notification[] => {
  const all = JSON.parse(localStorage.getItem(NOTIFICATIONS_KEY) || '[]');
  return all.filter((n: Notification) => n.userId === userId).sort((a: Notification, b: Notification) => 
    new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
  );
};

export const sendNotification = (notification: Omit<Notification, 'id' | 'timestamp' | 'isRead'>) => {
  const all = JSON.parse(localStorage.getItem(NOTIFICATIONS_KEY) || '[]');
  const newNotification: Notification = {
    ...notification,
    id: `notif-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
    timestamp: new Date().toISOString(),
    isRead: false
  };
  all.push(newNotification);
  localStorage.setItem(NOTIFICATIONS_KEY, JSON.stringify(all));
};

export const markAllNotificationsRead = (userId: string) => {
  const all = JSON.parse(localStorage.getItem(NOTIFICATIONS_KEY) || '[]');
  const updated = all.map((n: Notification) => n.userId === userId ? { ...n, isRead: true } : n);
  localStorage.setItem(NOTIFICATIONS_KEY, JSON.stringify(updated));
};

export const broadcastMessage = (title: string, message: string, filters?: { department?: string; year?: string }) => {
  const profiles = getProfiles();
  let count = 0;
  const allNotifications = JSON.parse(localStorage.getItem(NOTIFICATIONS_KEY) || '[]');

  profiles.forEach(p => {
    if (filters?.department && p.department !== filters.department) return;
    if (filters?.year && p.year !== filters.year) return;

    allNotifications.push({
      id: `notif-${Date.now()}-${p.userId}`,
      userId: p.userId,
      title, message, type: 'INFO', timestamp: new Date().toISOString(), isRead: false
    });
    count++;
  });
  localStorage.setItem(NOTIFICATIONS_KEY, JSON.stringify(allNotifications));
  return count;
};

// --- Logs & Analytics ---

export const logActivity = (userId: string, action: string) => {
  const logs = JSON.parse(localStorage.getItem(LOGS_KEY) || '[]');
  logs.push({ id: Date.now().toString(), userId, action, timestamp: new Date().toISOString() });
  localStorage.setItem(LOGS_KEY, JSON.stringify(logs));
};

export const formatBytes = (bytes: number) => {
  if (bytes === 0) return '0 Bytes';
  const k = 1024;
  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
};

