import { StudentProfile, User, Role, Notification, DEPARTMENTS, ActivityLog, AdminAuditLog } from '../types';

// Storage Keys
const USERS_KEY = 'profilehub_users';
const PROFILES_KEY = 'profilehub_profiles';
const NOTIFICATIONS_KEY = 'profilehub_notifications';
const AUTH_KEY = 'profilehub_auth_db';
const LOGS_KEY = 'profilehub_logs';
const AUDIT_KEY = 'profilehub_audit_logs';

// --- Generators ---
const randomInt = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;
const randomFloat = (min: number, max: number) => parseFloat((Math.random() * (max - min) + min).toFixed(2));
const randomItem = (arr: any[]) => arr[Math.floor(Math.random() * arr.length)];

// --- Initialization & Seeding ---
const initStorage = () => {
  const usersRaw = localStorage.getItem(USERS_KEY);
  let users: User[] = usersRaw ? JSON.parse(usersRaw) : [];
  let profiles: StudentProfile[] = JSON.parse(localStorage.getItem(PROFILES_KEY) || '[]');
  let updated = false;

  // 1. Seed Admin
  if (!users.find(u => u.username === 'admin')) {
    users.push({ id: 'admin-1', username: 'admin', role: Role.ADMIN, name: 'Super Admin', isActive: true });
    updated = true;
  }

  // 2. Seed Realistic Data (Target: 50 Students)
  if (profiles.length < 50) {
    const firstNames = ['Aarav', 'Vivaan', 'Aditya', 'Vihaan', 'Arjun', 'Sai', 'Reyansh', 'Ayaan', 'Krishna', 'Ishaan', 'Diya', 'Saanvi', 'Ananya', 'Aadhya', 'Pari', 'Anika', 'Navya', 'Riya', 'Myra', 'Ira'];
    const lastNames = ['Sharma', 'Verma', 'Patel', 'Reddy', 'Nair', 'Singh', 'Gupta', 'Kumar', 'Bhat', 'Rao', 'Iyer', 'Mehta', 'Jain', 'Chopra', 'Malhotra'];

    const countNeeded = 50 - profiles.length;

    for (let i = 0; i < countNeeded; i++) {
        const fName = randomItem(firstNames);
        const lName = randomItem(lastNames);
        const fullName = `${fName} ${lName}`;
        const dept = randomItem(DEPARTMENTS);
        const year = randomItem(['1', '2', '3', '4']);
        const rollNo = `7376${(25 - parseInt(year)).toString().padStart(2, '0')}BC${randomInt(100, 999)}`;
        const userId = `std-${Date.now()}-${i}`;

        // Add User
        users.push({ id: userId, username: rollNo, role: Role.STUDENT, name: fullName, isActive: true });

        // Add Auth
        const authDb = JSON.parse(localStorage.getItem(AUTH_KEY) || '{}');
        authDb[userId] = 'bitsathy'; 
        localStorage.setItem(AUTH_KEY, JSON.stringify(authDb));

        // Academic Data
        const cgpa = randomFloat(6.0, 9.9);
        const arrearCount = Math.random() > 0.8 ? randomInt(1, 4) : 0;
        const faPercent = randomInt(40, 100);
        const feesDue = Math.random() > 0.85 ? randomInt(10000, 150000) : 0;

        // Docs
        const docs = [];
        if (Math.random() > 0.3) docs.push({ id: `d-${i}-1`, name: 'Resume.pdf', type: 'Resume', fileType: 'pdf', size: 102400, uploadDate: '2025-02-01', url: '#', status: Math.random() > 0.8 ? 'Pending' : 'Approved' });
        if (Math.random() > 0.5) docs.push({ id: `d-${i}-2`, name: '12th_Mark_Sheet.jpg', type: 'Certificate', fileType: 'jpg', size: 204800, uploadDate: '2025-01-15', url: '#', status: 'Approved' });

        const semester = year === '1' ? 'Semester - II' : year === '2' ? 'Semester - IV' : year === '3' ? 'Semester - VI' : 'Semester - VIII';

        profiles.push({
            id: userId, userId: userId, fullName, username: rollNo, department: dept,
            email: `${rollNo.toLowerCase()}@bitsathy.ac.in`, phone: `98${randomInt(10000000, 99999999)}`,
            year, gender: Math.random() > 0.5 ? 'Male' : 'Female',
            education: [], skills: [], projects: [], documents: docs as any, certifications: [],
