import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../../App';
import { getProfiles, saveProfile, sendNotification, logAdminAction } from '../../services/storage';
import { StudentProfile, Document } from '../../types';
import { Button } from '../../components/ui/Button';
import { Check, X, Eye, FileText, Filter } from 'lucide-react';

const DocumentVerification: React.FC = () => {
  const { user } = useContext(AuthContext);
  const [queue, setQueue] = useState<{ profile: StudentProfile, doc: Document }[]>([]);

  useEffect(() => {
    loadQueue();
  }, []);

  const loadQueue = () => {
    const profiles = getProfiles();
    const pendingItems: { profile: StudentProfile, doc: Document }[] = [];
    profiles.forEach(p => {
      p.documents.forEach(d => {
        if (d.status === 'Pending') {
          pendingItems.push({ profile: p, doc: d });
        }
      });
    });
    setQueue(pendingItems);
  };

  const handleAction = (item: { profile: StudentProfile, doc: Document }, status: 'Approved' | 'Rejected') => {
    const reason = status === 'Rejected' ? prompt("Enter rejection reason for student:") : undefined;
    if (status === 'Rejected' && !reason) return;

    // Update Profile
    const updatedDocs = item.profile.documents.map(d => d.id === item.doc.id ? { ...d, status, feedback: reason } : d);
    const updatedProfile = { ...item.profile, documents: updatedDocs };
    saveProfile(updatedProfile);

    // Notify
    sendNotification({
      userId: item.profile.userId,
      type: status === 'Approved' ? 'SUCCESS' : 'ERROR',
      title: `Document ${status}`,
      message: `Your document ${item.doc.name} was ${status}. ${reason ? `Reason: ${reason}` : ''}`
    });

    logAdminAction(user!.id, 'DOC_VERIFY', `${status} document ${item.doc.name} for ${item.profile.username}`, item.profile.id);

    // Refresh UI
    loadQueue();
  };

  return (
    <div className="space-y-6">
       <div>
          <h1 className="text-2xl font-bold text-slate-800">Document Verification</h1>
          <p className="text-slate-500">Review pending uploads from students.</p>
       </div>

       {queue.length === 0 ? (
         <div className="bg-white p-12 rounded-xl shadow-sm text-center border border-slate-200">
            <div className="bg-green-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 text-green-600">
               <Check size={32} />
            </div>
            <h3 className="text-xl font-bold text-slate-800">All Caught Up!</h3>
            <p className="text-slate-500">No pending documents to review.</p>
         </div>
       ) : (
         <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {queue.map((item, idx) => (
               <div key={`${item.doc.id}-${idx}`} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
                  <div className="p-4 border-b bg-slate-50 flex justify-between items-start">
                     <div>
                        <h4 className="font-bold text-slate-800">{item.doc.type}</h4>
                        <p className="text-xs text-slate-500">{item.doc.uploadDate}</p>
                     </div>
                     <span className="bg-amber-100 text-amber-700 text-[10px] font-bold px-2 py-1 rounded uppercase">Pending</span>
                  </div>
                  <div className="p-4 flex-1">
                     <div className="flex items-center gap-3 mb-4">
                        <div className="h-10 w-10 bg-blue-100 rounded-full flex items-center justify-center text-blue-700 font-bold">{item.profile.fullName[0]}</div>
                        <div>
                           <p className="font-semibold text-sm text-slate-800">{item.profile.fullName}</p>
                           <p className="text-xs text-slate-500">{item.profile.username}</p>
                        </div>
                     </div>
                     <div className="bg-slate-100 rounded p-3 text-sm text-slate-600 flex items-center justify-between">
                        <span className="truncate max-w-[150px]">{item.doc.name}</span>
                        <span className="text-xs font-mono">{Math.round(item.doc.size/1024)} KB</span>
                     </div>
                  </div>
                  <div className="p-3 bg-slate-50 border-t flex gap-2">
                     <Button className="flex-1 bg-green-600 hover:bg-green-700" size="sm" onClick={() => handleAction(item, 'Approved')}>Approve</Button>
                     <Button className="flex-1 bg-red-600 hover:bg-red-700" size="sm" onClick={() => handleAction(item, 'Rejected')}>Reject</Button>
                     <Button variant="secondary" size="sm" onClick={() => alert("Preview Mock Open")}><Eye size={16}/></Button>
                  </div>
               </div>
            ))}
         </div>
       )}
    </div>
  );
};

export default DocumentVerification;

import React, { useContext } from 'react';
import { AuthContext } from '../../App';
import { getProfiles, logAdminAction } from '../../services/storage';
import { Button } from '../../components/ui/Button';
import { FileText, Download, Table, PieChart, Users } from 'lucide-react';

const Reports: React.FC = () => {
  const { user } = useContext(AuthContext);

  const generateReport = (type: string) => {
    const profiles = getProfiles();
    let data: string[][] = [];
    let headers: string[] = [];
    let filename = '';

    if (type === 'MASTER') {
       headers = ["Roll No", "Name", "Department", "Year", "CGPA", "Phone", "Email"];
       data = profiles.map(p => [p.username, p.fullName, p.department, p.year, p.academic.cgpa.toString(), p.phone, p.email]);
       filename = 'Master_Student_List.csv';
    } else if (type === 'ARREARS') {
       headers = ["Roll No", "Name", "Department", "Arrear Count"];
       data = profiles.filter(p => p.academic.arrearCount > 0).map(p => [p.username, p.fullName, p.department, p.academic.arrearCount.toString()]);
       filename = 'Arrear_Students_Report.csv';
    } else if (type === 'FEES') {
       headers = ["Roll No", "Name", "Fees Due (INR)"];
       data = profiles.filter(p => p.academic.feesDue > 0).map(p => [p.username, p.fullName, p.academic.feesDue.toString()]);
       filename = 'Fees_Due_Report.csv';
    } else if (type === 'PLACEMENT') {
       headers = ["Roll No", "Name", "Dept", "CGPA", "Placement FA %", "Status"];
       data = profiles.filter(p => p.academic.placementFaPercentage >= 75 && p.academic.cgpa >= 7.5 && p.academic.arrearCount === 0)
                      .map(p => [p.username, p.fullName, p.department, p.academic.cgpa.toString(), p.academic.placementFaPercentage.toString(), "Eligible"]);
       filename = 'Placement_Eligible_Report.csv';
    }

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), ...data.map(r => r.join(','))].join('\n');
    const link = document.createElement("a");
    link.setAttribute("href", encodeURI(csvContent));
    link.setAttribute("download", filename);
    document.body.appendChild(link);
    link.click();

    logAdminAction(user!.id, 'REPORT_GENERATE', `Generated ${type} report`);
  };

  const ReportCard = ({ title, desc, icon: Icon, type }: any) => (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow">
       <div className="flex items-start justify-between mb-4">
          <div className="p-3 bg-blue-50 text-blue-600 rounded-lg"><Icon size={24}/></div>
          <Button variant="outline" size="sm" onClick={() => generateReport(type)}><Download className="w-4 h-4 mr-2"/> Download</Button>
       </div>
       <h3 className="font-bold text-slate-800 mb-1">{title}</h3>
       <p className="text-sm text-slate-500">{desc}</p>
    </div>
  );

  return (
    <div className="space-y-6">
       <div>
          <h1 className="text-2xl font-bold text-slate-800">Reports Center</h1>
          <p className="text-slate-500">Generate and export system-wide reports.</p>
       </div>

       <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          <ReportCard title="Master Student List" desc="Complete database of all students with basic academic info." icon={Users} type="MASTER" />
          <ReportCard title="Arrear Report" desc="List of students with currently active arrears." icon={Table} type="ARREARS" />
          <ReportCard title="Placement Eligibility" desc="Students meeting FA > 75%, CGPA > 7.5 and no arrears." icon={PieChart} type="PLACEMENT" />
          <ReportCard title="Fees Dues List" desc="Students with outstanding fee payments." icon={FileText} type="FEES" />
       </div>
    </div>
  );
};

