// --- Core Data Access ---

export const getUsers = (): User[] => JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
export const getProfiles = (): StudentProfile[] => JSON.parse(localStorage.getItem(PROFILES_KEY) || '[]');

export const getProfileByUsername = (username: string): StudentProfile | undefined => {
  return getProfiles().find(p => p.username === username);
};

export const saveUser = (user: User) => {
  const users = getUsers();
  const idx = users.findIndex(u => u.id === user.id);
  if(idx >= 0) users[idx] = user;
  else users.push(user);
  localStorage.setItem(USERS_KEY, JSON.stringify(users));
};

export const savePassword = (userId: string, pass: string) => {
    const authDb = JSON.parse(localStorage.getItem(AUTH_KEY) || '{}');
    authDb[userId] = pass;
    localStorage.setItem(AUTH_KEY, JSON.stringify(authDb));
}

export const saveProfile = (profile: StudentProfile) => {
  const profiles = getProfiles();
  const index = profiles.findIndex(p => p.id === profile.id);
  if (index >= 0) profiles[index] = profile;
  else profiles.push(profile);
  localStorage.setItem(PROFILES_KEY, JSON.stringify(profiles));
};

// --- Notifications ---
export const getNotifications = (userId: string): Notification[] => {
  const all = JSON.parse(localStorage.getItem(NOTIFICATIONS_KEY) || '[]');
  return all.filter((n: Notification) => n.userId === userId).sort((a: Notification, b: Notification) => 
    new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
  );
};

export const sendNotification = (notification: Omit<Notification, 'id' | 'timestamp' | 'isRead'>) => {
  const all = JSON.parse(localStorage.getItem(NOTIFICATIONS_KEY) || '[]');
  const newNotification: Notification = {
    ...notification,
    id: `notif-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
    timestamp: new Date().toISOString(),
    isRead: false
  };
  all.push(newNotification);
  localStorage.setItem(NOTIFICATIONS_KEY, JSON.stringify(all));
};

export const markAllNotificationsRead = (userId: string) => {
  const all = JSON.parse(localStorage.getItem(NOTIFICATIONS_KEY) || '[]');
  const updated = all.map((n: Notification) => n.userId === userId ? { ...n, isRead: true } : n);
  localStorage.setItem(NOTIFICATIONS_KEY, JSON.stringify(updated));
};

// --- Logs & Audit ---
export const logActivity = (userId: string, action: string) => {
  const logs = JSON.parse(localStorage.getItem(LOGS_KEY) || '[]');
  logs.push({ id: Date.now().toString(), userId, action, timestamp: new Date().toISOString() });
  localStorage.setItem(LOGS_KEY, JSON.stringify(logs));
};

export const logAdminAction = (adminId: string, action: string, details: string, targetId?: string) => {
  const auditLogs = JSON.parse(localStorage.getItem(AUDIT_KEY) || '[]');
  const newLog: AdminAuditLog = {
      id: `audit-${Date.now()}`,
      adminId,
      action,
      details,
      targetId,
      timestamp: new Date().toISOString(),
      ipAddress: '192.168.1.10'
  };
  auditLogs.push(newLog);
  localStorage.setItem(AUDIT_KEY, JSON.stringify(auditLogs));
};

export const getAdminLogs = (): AdminAuditLog[] => {
    return JSON.parse(localStorage.getItem(AUDIT_KEY) || '[]').sort((a: AdminAuditLog, b: AdminAuditLog) => 
        new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
    );
};

export const formatBytes = (bytes: number) => {
  if (bytes === 0) return '0 Bytes';
  const k = 1024;
  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
};

export const sendOTP = async (email: string): Promise<string> => {
    await new Promise(resolve => setTimeout(resolve, 1000));
    const otp = Math.floor(1000 + Math.random() * 9000).toString();
    console.log(`[SMTP MOCK] OTP sent to ${email}: ${otp}`);
    alert(`[DEMO] OTP sent to ${email}: ${otp}`);
    return otp;
}

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'outline' | 'ghost' | 'success';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  className = '', 
  isLoading,
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-lg font-medium transition-all focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 disabled:opacity-50 disabled:pointer-events-none shadow-md";

  const variants = {
    primary: "bg-purple-600 text-white hover:bg-purple-700 focus:ring-purple-500 shadow-purple-900/20",
    secondary: "bg-slate-800 text-slate-200 border border-slate-700 hover:bg-slate-700 focus:ring-purple-500",
    danger: "bg-red-600 text-white hover:bg-red-700 focus:ring-red-500",
    success: "bg-emerald-600 text-white hover:bg-emerald-700 focus:ring-emerald-500",
    outline: "border-2 border-purple-600 text-purple-400 hover:bg-purple-900/20 focus:ring-purple-500",
    ghost: "text-slate-400 hover:bg-slate-800 hover:text-white focus:ring-slate-500 shadow-none"
  };

  const sizes = {
    sm: "h-8 px-3 text-xs",
    md: "h-10 px-4 py-2 text-sm",
    lg: "h-12 px-6 text-base"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading ? (
        <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
