                     <ul className="divide-y divide-slate-800">
                       {notifications.map((notif) => (
                         <li key={notif.id} className={`p-4 hover:bg-slate-800 transition-colors ${!notif.isRead ? 'bg-slate-800/50' : ''}`}>
