import React, { useState, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../App';
import { Role, StudentProfile, DEPARTMENTS } from '../types';
import { saveUser, saveProfile, getUsers } from '../services/storage';
import { Input, Select } from '../components/ui/Input';
import { Button } from '../components/ui/Button';
import { GraduationCap } from 'lucide-react';

const Register: React.FC = () => {
  const navigate = useNavigate();
  const { login } = useContext(AuthContext);

  const [formData, setFormData] = useState({
    fullName: '',
    username: '', // Roll No
    department: '',
    email: '',
    phone: '',
    password: '',
    confirmPassword: '',
    gender: 'Male',
    year: '1',
    semester: 'Semester - I'
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const validate = () => {
    const users = getUsers();
    if (users.find(u => u.username === formData.username)) return "Roll Number already registered";
    if (!formData.email.endsWith('@bitsathy.ac.in')) return "Email must match @bitsathy.ac.in domain";
    if (!/^\d{10}$/.test(formData.phone)) return "Phone number must be exactly 10 digits";
    if (formData.password !== formData.confirmPassword) return "Passwords do not match";
    if (formData.password.length < 6) return "Password must be at least 6 characters";
    return null;
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const validationError = validate();
    if (validationError) {
      setError(validationError);
      return;
    }

    setLoading(true);
    await new Promise(resolve => setTimeout(resolve, 800));

    const userId = `std-${formData.username}`;
    const newUser = { id: userId, username: formData.username, role: Role.STUDENT, name: formData.fullName, isActive: true };

    const authDb = JSON.parse(localStorage.getItem('profilehub_auth_db_v2') || '{}');
    authDb[userId] = formData.password;
    localStorage.setItem('profilehub_auth_db_v2', JSON.stringify(authDb));

    const newProfile: StudentProfile = {
      id: userId, userId: userId, fullName: formData.fullName, username: formData.username,
      department: formData.department, email: formData.email, phone: formData.phone,
      year: formData.year, gender: formData.gender as any, education: [], skills: [], projects: [],
      documents: [], certifications: [], privacy: { hidePhone: false }, completenessScore: 10,
      semester: formData.semester,
      status: 'Continuing',
      academic: {
        cgpa: 0,
        placementFaPercentage: 0,
        arrearCount: 0,
        feesDue: 0,
        history: []
      },
      biometricLogs: []
    };

    saveUser(newUser);
    saveProfile(newProfile);
    login(newUser);
    setLoading(false);
    navigate('/student/dashboard');
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-950 py-12 px-4">
      <div className="max-w-2xl w-full bg-slate-900 p-8 rounded-2xl shadow-2xl border border-slate-800">
        <div className="text-center mb-8">
          <GraduationCap className="mx-auto h-10 w-10 text-blue-500" />
          <h2 className="mt-2 text-3xl font-bold text-white">Student Registration</h2>
          <p className="text-slate-400">Join the ProfileHub System</p>
        </div>

        {error && <div className="bg-red-900/20 border border-red-900/50 text-red-400 p-3 rounded mb-6 text-center text-sm">{error}</div>}

        <form onSubmit={handleRegister} className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <Input label="Full Name" name="fullName" required value={formData.fullName} onChange={handleChange} />
            <Input label="Roll Number" name="username" required value={formData.username} onChange={handleChange} placeholder="e.g. 7376232AL..." />
            <Input label="College Email" type="email" name="email" required value={formData.email} onChange={handleChange} placeholder="@bitsathy.ac.in" />
            <Input label="Phone Number" type="tel" name="phone" required value={formData.phone} onChange={handleChange} maxLength={10} />

            <div className="md:col-span-2">
              <Select label="Department" name="department" required value={formData.department} onChange={handleChange}
                options={DEPARTMENTS.map(d => ({ value: d, label: d }))}
              />
            </div>

            <Select label="Batch / Year" name="year" required value={formData.year} onChange={handleChange}
              options={[{value:'1', label:'1st Year'},{value:'2', label:'2nd Year'},{value:'3', label:'3rd Year'},{value:'4', label:'4th Year'}]}
            />
            <Select label="Gender" name="gender" required value={formData.gender} onChange={handleChange}
              options={[{value:'Male', label:'Male'},{value:'Female', label:'Female'},{value:'Other', label:'Other'}]}
            />
            <Input label="Password" type="password" name="password" required value={formData.password} onChange={handleChange} />
            <Input label="Confirm Password" type="password" name="confirmPassword" required value={formData.confirmPassword} onChange={handleChange} />
          </div>

          <div className="flex gap-4 pt-4 border-t border-slate-800">
            <Button type="button" variant="ghost" className="w-full" onClick={() => navigate('/login')}>Back to Login</Button>
            <Button type="submit" className="w-full" isLoading={loading}>Register Account</Button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Register;

