import React, { useEffect, useState } from 'react';
import { getProfiles } from '../../services/storage';
import { StudentProfile } from '../../types';
import { 
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, PieChart, Pie, Cell, Legend
} from 'recharts';
import { Users, FileText, CheckCircle, TrendingUp, AlertTriangle, DollarSign, Award, BookOpen } from 'lucide-react';

const Dashboard: React.FC = () => {
  const [profiles, setProfiles] = useState<StudentProfile[]>([]);

  useEffect(() => {
    setProfiles(getProfiles());
  }, []);

  if (profiles.length === 0) return <div>Loading Analytics...</div>;

  // --- Calculations ---
  const totalStudents = profiles.length;
  const avgCgpa = (profiles.reduce((acc, p) => acc + (p.academic.cgpa || 0), 0) / totalStudents).toFixed(2);
  const studentsWithArrears = profiles.filter(p => p.academic.arrearCount > 0).length;
  const totalFeesDue = profiles.reduce((acc, p) => acc + p.academic.feesDue, 0);

  // Charts Data
  const deptData = profiles.reduce((acc, p) => {
    const shortDept = p.department.split(' ').map(w => w[0]).join(''); 
    acc[shortDept] = (acc[shortDept] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const deptChartData = Object.keys(deptData).slice(0, 8).map(key => ({ name: key, value: deptData[key] }));

  const cgpaDistribution = [
      { name: '9-10', value: profiles.filter(p => p.academic.cgpa >= 9).length },
      { name: '8-9', value: profiles.filter(p => p.academic.cgpa >= 8 && p.academic.cgpa < 9).length },
      { name: '7-8', value: profiles.filter(p => p.academic.cgpa >= 7 && p.academic.cgpa < 8).length },
      { name: '6-7', value: profiles.filter(p => p.academic.cgpa >= 6 && p.academic.cgpa < 7).length },
      { name: '< 6', value: profiles.filter(p => p.academic.cgpa < 6).length },
  ];

  const topStudents = [...profiles].sort((a, b) => b.academic.cgpa - a.academic.cgpa).slice(0, 5);

  const COLORS = ['#3b82f6', '#2563eb', '#1d4ed8', '#1e40af', '#1e3a8a', '#172554', '#172554'];

  return (
    <div className="space-y-6 animate-fade-in">
      <div>
        <h1 className="text-2xl font-bold text-white">Analytics Dashboard</h1>
        <p className="text-slate-400">Overview of student performance and system status.</p>
      </div>

      {/* Top Stats Row */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-slate-900 p-4 rounded-xl shadow-lg border-l-4 border-blue-600 flex justify-between items-center border border-slate-800">
           <div><p className="text-xs text-slate-400 uppercase font-bold">Total Students</p><p className="text-2xl font-bold text-white">{totalStudents}</p></div>
           <div className="p-3 bg-slate-800 text-blue-500 rounded-full"><Users size={20}/></div>
        </div>
        <div className="bg-slate-900 p-4 rounded-xl shadow-lg border-l-4 border-emerald-500 flex justify-between items-center border border-slate-800">
           <div><p className="text-xs text-slate-400 uppercase font-bold">Avg. CGPA</p><p className="text-2xl font-bold text-white">{avgCgpa}</p></div>
           <div className="p-3 bg-slate-800 text-emerald-500 rounded-full"><TrendingUp size={20}/></div>
        </div>
        <div className="bg-slate-900 p-4 rounded-xl shadow-lg border-l-4 border-amber-500 flex justify-between items-center border border-slate-800">
           <div><p className="text-xs text-slate-400 uppercase font-bold">Arrears Active</p><p className="text-2xl font-bold text-white">{studentsWithArrears}</p></div>
           <div className="p-3 bg-slate-800 text-amber-500 rounded-full"><AlertTriangle size={20}/></div>
        </div>
        <div className="bg-slate-900 p-4 rounded-xl shadow-lg border-l-4 border-red-500 flex justify-between items-center border border-slate-800">
           <div><p className="text-xs text-slate-400 uppercase font-bold">Fees Due (Total)</p><p className="text-xl font-bold text-white">₹ {(totalFeesDue/100000).toFixed(1)} L</p></div>
           <div className="p-3 bg-slate-800 text-red-500 rounded-full"><DollarSign size={20}/></div>
        </div>
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
         {/* CGPA Dist */}
         <div className="bg-slate-900 p-6 rounded-xl shadow-lg border border-slate-800">
            <h3 className="font-bold text-slate-200 mb-4 flex items-center gap-2"><Award className="w-4 h-4 text-blue-500"/> CGPA Distribution</h3>
            <div className="h-64 w-full">
              <ResponsiveContainer width="100%" height="100%">
                 <BarChart data={cgpaDistribution}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#334155"/>
                    <XAxis dataKey="name" tick={{fontSize: 12, fill: '#94a3b8'}} />
                    <YAxis tick={{fontSize: 12, fill: '#94a3b8'}} />
                    <Tooltip cursor={{fill: '#1e293b'}} contentStyle={{backgroundColor: '#0f172a', borderRadius: '8px', border: '1px solid #334155', color: 'white'}} />
                    <Bar dataKey="value" fill="#2563eb" radius={[4,4,0,0]} />
                 </BarChart>
              </ResponsiveContainer>
            </div>
         </div>

         {/* Dept Dist */}
         <div className="bg-slate-900 p-6 rounded-xl shadow-lg border border-slate-800">
