      </div>

      {/* Bottom Section: Top Students & Status */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
         <div className="lg:col-span-2 bg-slate-900 rounded-xl shadow-lg border border-slate-800 overflow-hidden">
