                               {notif.type === 'ERROR' && <AlertCircle className="w-5 h-5 text-red-500" />}
                               {notif.type === 'INFO' && <Info className="w-5 h-5 text-blue-500" />}
                             </div>
                             <div>
                               <p className="text-sm font-semibold text-slate-800">{notif.title}</p>
                               <p className="text-sm text-slate-500 mt-0.5">{notif.message}</p>
                               <p className="text-xs text-slate-400 mt-2">{new Date(notif.timestamp).toLocaleString()}</p>
