                       ))}
                     </ul>
                   )}
                 </div>
               </div>
             )}
           </div>
        </div>

        <div className="max-w-7xl mx-auto pt-4 md:pt-0">
           <Outlet />
        </div>
      </main>

      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-0 md:hidden" onClick={() => setIsSidebarOpen(false)} />}
    </div>
  );
};

