const Dashboard: React.FC = () => {
  const [profiles, setProfiles] = useState<StudentProfile[]>([]);

  useEffect(() => {
    setProfiles(getProfiles());
  }, []);

  if (profiles.length === 0) return <div>Loading Analytics...</div>;

  // --- Calculations ---
  const totalStudents = profiles.length;
  const avgCgpa = (profiles.reduce((acc, p) => acc + (p.academic.cgpa || 0), 0) / totalStudents).toFixed(2);
  const studentsWithArrears = profiles.filter(p => p.academic.arrearCount > 0).length;
  const totalFees Due = profiles.reduce((acc, p) => acc + p.academic.feesDue, 0);

  // Charts Data
  const deptData = profiles.reduce((acc, p) => {
    const shortDept = p.department.split(' ').map(w => w[0]).join(''); 
    acc[shortDept] = (acc[shortDept] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const deptChartData = Object.keys(deptData).slice(0, 8).map(key => ({ name: key, value: deptData[key] }));

  const cgpaDistribution = [
      { name: '9-10', value: profiles.filter(p => p.academic.cgpa >= 9).length },
      { name: '8-9', value: profiles.filter(p => p.academic.cgpa >= 8 && p.academic.cgpa < 9).length },
      { name: '7-8', value: profiles.filter(p => p.academic.cgpa >= 7 && p.academic.cgpa < 8).length },
      { name: '6-7', value: profiles.filter(p => p.academic.cgpa >= 6 && p.academic.cgpa < 7).length },
      { name: '< 6', value: profiles.filter(p => p.academic.cgpa < 6).length },
  ];

  const topStudents = [...profiles].sort((a, b) => b.academic.cgpa - a.academic.cgpa).slice(0, 5);

  const COLORS = ['#1e3a8a', '#1e40af', '#2563eb', '#3b82f6', '#60a5fa', '#93c5fd', '#bfdbfe'];

  return (
    <div className="space-y-6 animate-fade-in">
      <div>
        <h1 className="text-2xl font-bold text-slate-800">Analytics Dashboard</h1>
        <p className="text-slate-500">Overview of student performance and system status.</p>
