           <div><p className="text-xs text-slate-500 uppercase font-bold">Total Students</p><p className="text-2xl font-bold text-slate-800">{totalStudents}</p></div>
           <div className="p-3 bg-blue-50 text-blue-900 rounded-full"><Users size={20}/></div>
        </div>
        <div className="bg-white p-4 rounded-xl shadow-sm border-l-4 border-emerald-500 flex justify-between items-center border border-slate-200">
           <div><p className="text-xs text-slate-500 uppercase font-bold">Avg. CGPA</p><p className="text-2xl font-bold text-slate-800">{avgCgpa}</p></div>
           <div className="p-3 bg-emerald-50 text-emerald-600 rounded-full"><TrendingUp size={20}/></div>
        </div>
        <div className="bg-white p-4 rounded-xl shadow-sm border-l-4 border-amber-500 flex justify-between items-center border border-slate-200">
           <div><p className="text-xs text-slate-500 uppercase font-bold">Arrears Active</p><p className="text-2xl font-bold text-slate-800">{studentsWithArrears}</p></div>
           <div className="p-3 bg-amber-50 text-amber-600 rounded-full"><AlertTriangle size={20}/></div>
        </div>
        <div className="bg-white p-4 rounded-xl shadow-sm border-l-4 border-red-500 flex justify-between items-center border border-slate-200">
           <div><p className="text-xs text-slate-500 uppercase font-bold">Fees Due (Total)</p><p className="text-xl font-bold text-slate-800">₹ {(totalFeesDue/100000).toFixed(1)} L</p></div>
