import { 
  User, FileText, Briefcase, LayoutDashboard, LogOut, Menu, X, FileBadge, Bell, CheckCircle, AlertCircle, Info, Home
} from 'lucide-react';

const StudentLayout: React.FC = () => {
  const { user, logout } = useContext(AuthContext);
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [showNotifications, setShowNotifications] = useState(false);
  const notifRef = useRef<HTMLDivElement>(null);

  const profile = user ? getProfileByUsername(user.username) : null;

  useEffect(() => {
    if (user) {
      setNotifications(getNotifications(user.id));
      const interval = setInterval(() => setNotifications(getNotifications(user.id)), 5000);
      return () => clearInterval(interval);
    }
  }, [user]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notifRef.current && !notifRef.current.contains(event.target as Node)) setShowNotifications(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const unreadCount = notifications.filter(n => !n.isRead).length;

  return (
    <div className="min-h-screen bg-white flex flex-col md:flex-row font-sans text-slate-800">
      {/* Mobile Header */}
      <div className="md:hidden bg-white text-blue-900 p-4 flex justify-between items-center z-20 shadow-sm border-b border-slate-200">
        <h1 className="text-xl font-bold tracking-wide flex items-center gap-2">
           <div className="w-8 h-8 bg-blue-900 rounded-lg flex items-center justify-center text-white"><LayoutDashboard size={18}/></div>
           ProfileHub
        </h1>
        <div className="flex items-center gap-4">
           <button onClick={() => setShowNotifications(!showNotifications)} className="relative p-1">
             <Bell className="w-6 h-6 text-slate-600" />
             {unreadCount > 0 && <span className="absolute top-0 right-0 w-2.5 h-2.5 bg-red-500 rounded-full border border-white"></span>}
           </button>
           <button onClick={() => setIsSidebarOpen(!isSidebarOpen)}><Menu className="text-slate-800"/></button>
        </div>
      </div>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-10 w-64 bg-white text-slate-800 shadow-xl transform transition-transform duration-300 ease-in-out border-r border-slate-200
        md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="h-full flex flex-col">
          <div className="p-6 border-b border-slate-100">
            <h1 className="text-2xl font-bold flex items-center gap-2 tracking-tight text-blue-900">
              <div className="w-8 h-8 bg-blue-900 rounded-lg flex items-center justify-center text-white shadow-blue-900/20 shadow-lg">
                <LayoutDashboard size={18}/>
              </div>
              ProfileHub
            </h1>
          </div>

          <div className="p-6 border-b border-slate-100 bg-slate-50/50">
            <div className="flex items-center gap-3">
              <div className="h-10 w-10 rounded-full bg-blue-100 flex items-center justify-center font-bold text-blue-900 border border-blue-200">
                {user?.name.charAt(0)}
              </div>
              <div className="overflow-hidden">
                <p className="font-semibold truncate text-slate-900">{user?.name}</p>
                <p className="text-xs text-slate-500 truncate">{user?.username}</p>
              </div>
            </div>
            {profile && (
               <div className="mt-4">
                 <div className="flex justify-between text-xs text-slate-500 mb-1">
                   <span>Profile Completeness</span>
                   <span className="text-blue-700 font-bold">{profile.completenessScore}%</span>
                 </div>
                 <div className="w-full bg-slate-200 rounded-full h-1.5">
                   <div className="bg-blue-600 h-1.5 rounded-full transition-all duration-1000" style={{ width: `${profile.completenessScore}%` }}></div>
                 </div>
               </div>
            )}
          </div>

          <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
            {[
              { path: '/student/dashboard', label: 'Dashboard', icon: Home },
              { path: '/student/profile', label: 'Profile Management', icon: User },
              { path: '/student/education', label: 'Education & Skills', icon: Briefcase },
              { path: '/student/documents', label: 'Documents & Uploads', icon: FileText },
              { path: '/student/resume', label: 'Resume Builder', icon: FileBadge },
            ].map((item) => (
              <NavLink
                key={item.path}
                to={item.path}
                onClick={() => setIsSidebarOpen(false)}
                className={({ isActive }) =>
                  `flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-colors ${
                    isActive
                      ? 'bg-blue-50 text-blue-900 shadow-sm border border-blue-100'
                      : 'text-slate-500 hover:bg-slate-50 hover:text-slate-900'
                  }`
                }
              >
                <item.icon className={`h-5 w-5 ${ ({isActive}:any) => isActive ? 'text-blue-700' : 'text-slate-400' }`} />
                {item.label}
              </NavLink>
            ))}
          </nav>

          <div className="p-4 border-t border-slate-100">
            <button
              onClick={() => { logout(); navigate('/login'); }}
              className="flex w-full items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium text-red-600 hover:bg-red-50 transition-colors"
            >
              <LogOut className="h-5 w-5" />
              Logout
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto h-[calc(100vh-64px)] md:h-screen relative bg-white">
        {/* Desktop Header Bell */}
        <div className="hidden md:flex justify-end mb-6 absolute top-6 right-8 z-30" ref={notifRef}>
           <div className="relative">
             <button 
               onClick={() => setShowNotifications(!showNotifications)} 
               className="p-2 rounded-full bg-white shadow-sm border border-slate-200 text-slate-500 hover:text-blue-600 transition-colors"
             >
               <Bell className="w-5 h-5" />
               {unreadCount > 0 && (
                 <span className="absolute -top-1 -right-1 flex h-4 w-4 items-center justify-center rounded-full bg-red-500 text-[10px] font-bold text-white shadow-sm animate-pulse">
                   {unreadCount}
                 </span>
               )}
             </button>

             {/* Dropdown */}
             {showNotifications && (
               <div className="absolute right-0 mt-3 w-96 bg-white rounded-xl shadow-2xl border border-slate-200 overflow-hidden z-50 animate-fade-in-down">
                 <div className="p-4 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
                   <h3 className="font-semibold text-slate-800">Notifications</h3>
                   {unreadCount > 0 && (
                     <button onClick={() => { markAllNotificationsRead(user!.id); setNotifications(prev => prev.map(n => ({ ...n, isRead: true }))); }} className="text-xs text-blue-600 font-medium hover:underline">
                       Mark all read
                     </button>
                   )}
                 </div>
                 <div className="max-h-96 overflow-y-auto">
                   {notifications.length === 0 ? (
                     <div className="p-8 text-center text-slate-400">
                       <Bell className="w-8 h-8 mx-auto mb-2 opacity-20" />
                       <p className="text-sm">No new notifications</p>
                     </div>
