import React, { useState, useContext } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { AuthContext } from '../App';
import { Role, User } from '../types';
import { getUsers, logActivity } from '../services/storage';
import { Input } from '../components/ui/Input';
import { Button } from '../components/ui/Button';
import { GraduationCap, Lock, User as UserIcon, Eye, EyeOff } from 'lucide-react';

const Login: React.FC = () => {
  const [role, setRole] = useState<Role>(Role.STUDENT);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const [error, setError] = useState('');
  const { login } = useContext(AuthContext);
  const navigate = useNavigate();

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    // Admin
    if (role === Role.ADMIN) {
      if (username === 'admin' && password === 'admin123') {
        const adminUser: User = { id: 'admin-1', username: 'admin', role: Role.ADMIN, name: 'College Admin', isActive: true };
        login(adminUser);
        navigate('/admin');
        return;
      } else {
        setError('Invalid admin credentials. Use admin / admin123');
        return;
      }
    }

    // Student Login
    const users = getUsers();
    const user = users.find(u => u.username === username && u.role === Role.STUDENT);
    const storedAuth = JSON.parse(localStorage.getItem('profilehub_auth_db_v2') || '{}');

    if (user && user.isActive && storedAuth[user.id] === password) {
      login(user);
      logActivity(user.id, "Login Successful");
      navigate('/student/dashboard');
    } else {
      setError('Invalid Roll No or Password. Try 7376232AL206 / Swetha@206');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-white py-12 px-4 sm:px-6 lg:px-8 relative overflow-hidden">
      {/* Background Shapes */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-50 rounded-full blur-3xl opacity-60"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-indigo-50 rounded-full blur-3xl opacity-60"></div>

      <div className="max-w-md w-full space-y-8 bg-white p-8 rounded-2xl shadow-xl border border-slate-100 z-10">
        <div className="text-center">
          <div className="mx-auto h-16 w-16 bg-blue-50 rounded-full flex items-center justify-center border-2 border-blue-800 shadow-sm">
             <GraduationCap className="h-10 w-10 text-blue-800" />
          </div>
          <h2 className="mt-4 text-3xl font-extrabold text-slate-900 tracking-tight">ProfileHub</h2>
          <p className="mt-1 text-sm text-slate-500">Student Profile Management System</p>
        </div>

        <div className="flex bg-slate-50 p-1 rounded-lg border border-slate-100">
          <button
            onClick={() => setRole(Role.STUDENT)}
            className={`flex-1 py-2 text-sm font-semibold rounded-md transition-all ${
              role === Role.STUDENT ? 'bg-white text-blue-900 shadow-sm border border-slate-200' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            Student Login
          </button>
          <button
            onClick={() => setRole(Role.ADMIN)}
            className={`flex-1 py-2 text-sm font-semibold rounded-md transition-all ${
              role === Role.ADMIN ? 'bg-white text-blue-900 shadow-sm border border-slate-200' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            Admin Login
          </button>
        </div>

        <form className="mt-6 space-y-6" onSubmit={handleLogin}>
          <div className="space-y-4">
            <div className="relative">
              <UserIcon className="absolute top-9 left-3 h-5 w-5 text-slate-400" />
              <Input
                label={role === Role.ADMIN ? "Username" : "Roll Number"}
                type="text"
                required
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                placeholder={role === Role.ADMIN ? "admin" : "e.g. 7376232AL206"}
                className="pl-10"
              />
            </div>
            <div className="relative">
              <Lock className="absolute top-9 left-3 h-5 w-5 text-slate-400" />
              <Input
                label="Password"
                type={showPass ? "text" : "password"}
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
                className="pl-10 pr-10"
              />
              <button type="button" onClick={() => setShowPass(!showPass)} className="absolute top-9 right-3 text-slate-400 hover:text-blue-600">
                {showPass ? <EyeOff size={18}/> : <Eye size={18}/>}
              </button>
            </div>
          </div>

          <div className="flex items-center justify-between">
            <div className="flex items-center">
              <input id="remember-me" type="checkbox" className="h-4 w-4 text-blue-600 focus:ring-blue-500 border-slate-300 rounded" />
              <label htmlFor="remember-me" className="ml-2 block text-sm text-slate-600">Remember me</label>
            </div>
            {role === Role.STUDENT && (
              <div className="text-sm">
                <Link to="/forgot-password" className="font-medium text-blue-700 hover:text-blue-600">
                  Forgot password?
                </Link>
              </div>
            )}
          </div>

          {error && <div className="text-red-600 text-sm text-center bg-red-50 p-3 rounded-lg border border-red-200">{error}</div>}

          <Button type="submit" className="w-full h-12 text-base shadow-lg shadow-blue-900/10" size="lg">
            Sign in securely
          </Button>

          {role === Role.STUDENT && (
            <div className="text-center text-sm mt-4">
              <span className="text-slate-500">New student? </span>
              <Link to="/register" className="font-bold text-blue-700 hover:underline">
                Register Account
              </Link>
            </div>
          )}
        </form>
      </div>
    </div>
  );
};

