            <div className="relative">
              <Lock className="absolute top-9 left-3 h-5 w-5 text-slate-400" />
              <Input
                label="Password"
                type={showPass ? "text" : "password"}
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
